function renderPaymentPreviewHostedFields(providerLabel = '') {
  return `
    <div class="rstk-checkout-fields rstk-checkout-fields-mock" aria-hidden="true">
      <p class="rstk-checkout-secure">
        Se abrirá el checkout seguro de ${escapeHtml(providerLabel)} para completar el pago.
      </p>
    </div>
  `
}

function renderPaymentPreviewBlock(block = {}) {
  const settings = block.settings || {}
  const paymentGate = getPaymentGateFromBlock(block)
  const layout = normalizePaymentBlockLayout(settings.paymentLayout || settings.payment_layout)
  const productName = cleanString(paymentGate.productName || block.content || block.label) || 'Pago requerido'
  const description = cleanString(paymentGate.description) || ''
  const buttonLabel = cleanString(paymentGate.buttonText) || 'Pagar'
  const amountText = formatPaymentAmount(paymentGate.amount, paymentGate.currency)
  const isSubscriptionCheckout = paymentGate.billingType === 'subscription'
  const amountDisplayText = isSubscriptionCheckout ? `${amountText} / ${formatPaymentSubscriptionCadence(paymentGate)}` : amountText
  const gateway = cleanString(paymentGate.gateway)
  const providerLabel = getPaymentGatewayLabel(gateway)
  const gateEnabled = isPaymentGateEnabled(paymentGate)
  const showKicker = settings.paymentShowGatewayName !== false
  const showSecure = settings.paymentShowSecureNote !== false
  const showCountry = settings.paymentShowCountry !== false
  const secureNote = cleanString(settings.paymentSecureNote) || PAYMENT_SECURE_NOTE_DEFAULT
  const providerCollectsIdentity = gateway === 'clip' || gateway === 'mercadopago' || gateway === 'rebill'
  const collectEmail = isSubscriptionCheckout ? true : settings.paymentCollectEmail !== false
  const collectPhone = isSubscriptionCheckout ? true : settings.paymentCollectPhone !== false
  const showIdentityFields = (isSubscriptionCheckout || !providerCollectsIdentity) && (collectEmail || collectPhone)
  const checkoutAlign = blockHorizontalAlign(settings, 'paymentTextAlign', 'left')
  const fieldTextColor = cleanString(settings.paymentFieldTextColor).replace(/[^a-zA-Z0-9#().,%\s/-]/g, '')
  const payButtonAlign = blockButtonAlign(settings, 'full')
  const payButtonWidthPct = Number(settings.buttonWidth)
  const payWidth = payButtonAlign === 'full' || !(payButtonWidthPct > 0) ? '100%' : `${Math.min(100, Math.max(10, Math.round(payButtonWidthPct)))}%`
  const payJustify = payWidth === '100%' ? 'stretch' : (payButtonAlign === 'left' ? 'start' : payButtonAlign === 'right' ? 'end' : 'center')
  const checkoutStyle = `--rstk-checkout-align:${checkoutAlign};--rstk-checkout-pay-width:${payWidth};--rstk-checkout-pay-justify:${payJustify}${fieldTextColor ? `;--rstk-checkout-field-text:${fieldTextColor}` : ''}`
  const fields = isSubscriptionCheckout || gateway === 'clip' || gateway === 'rebill'
    ? renderPaymentPreviewHostedFields(providerLabel)
    : gateway === 'mercadopago'
      ? renderPaymentPreviewMercadoPagoBrick()
      : renderPaymentPreviewCardFields({
        isStripe: gateway === 'stripe' || !gateway,
        isConekta: gateway === 'conekta',
        collectEmail: showIdentityFields && collectEmail,
        collectPhone: showIdentityFields && collectPhone,
        showCountry
      })
  const paymentTestGuide = paymentGate.mode === 'test' ? renderPaymentTestGuide(paymentGate.gateway) : ''

  return `
    <section class="rstk-payment-block rstk-payment-${escapeHtml(layout)}"
      style="${escapeHtml(checkoutStyle)}"
      data-rstk-payment-block
      data-rstk-payment-preview="true"
      data-payment-block-id="${escapeHtml(block.id || '')}"
      data-provider="${escapeHtml(paymentGate.gateway)}"
      data-billing-type="${isSubscriptionCheckout ? 'subscription' : 'single'}"
      data-amount="${escapeHtml(String(paymentGate.amount || ''))}"
      data-currency="${escapeHtml(paymentGate.currency || '')}">
      ${gateEnabled ? '' : '<span class="rstkPaymentUnpublishedBadge" aria-hidden="true">No visible en el sitio publicado</span>'}
      <div class="rstk-checkout-card">
        <div class="rstk-checkout-inner">
          <div class="rstk-checkout-head">
            ${showKicker ? `<span class="rstk-payment-kicker">${escapeHtml(providerLabel)}</span>` : ''}
            <strong class="rstk-checkout-title">${escapeHtml(productName)}</strong>
            ${description ? `<p class="rstk-checkout-desc">${escapeHtml(description)}</p>` : ''}
            <span class="rstk-checkout-amount">${escapeHtml(amountDisplayText)}</span>
          </div>
          ${paymentGate.mode === 'test' ? '<p class="rstk-checkout-testbadge">Modo prueba · no es un cobro real</p>' : ''}
          <div class="rstk-checkout-body">
            ${fields}
            ${gateway === 'mercadopago' ? '' : `
              <button type="button" class="rstk-button-link rstk-checkout-pay" disabled>
                ${renderSubmitButtonContent(`${buttonLabel} · ${amountDisplayText}`, '', settings)}
              </button>
            `}
            ${paymentTestGuide}
            ${showSecure ? `<p class="rstk-checkout-secure">${escapeHtml(secureNote)}</p>` : ''}
          </div>
        </div>
      </div>
    </section>
  `
}

function renderPaymentBlock(block = {}, context = {}) {
  const settings = block.settings || {}
  const paymentGate = getPaymentGateFromBlock(block)
  if (context.importedNativePreviewMock) return renderPaymentPreviewBlock(block)
  if (!isPaymentGateEnabled(paymentGate)) return ''
  const layout = normalizePaymentBlockLayout(settings.paymentLayout || settings.payment_layout)
  const pages = Array.isArray(context.pages) ? context.pages : normalizeSitePages(context.site)
  const pageId = getBlockPageId(block, pages)
  const siteId = cleanString(context.site?.id)
  const productName = cleanString(paymentGate.productName || block.content || block.label) || 'Pago requerido'
  const description = cleanString(paymentGate.description) || ''
  const buttonLabel = cleanString(paymentGate.buttonText) || 'Pagar'
  const amountText = formatPaymentAmount(paymentGate.amount, paymentGate.currency)
  const isSubscriptionCheckout = paymentGate.billingType === 'subscription'
  const amountDisplayText = isSubscriptionCheckout ? `${amountText} / ${formatPaymentSubscriptionCadence(paymentGate)}` : amountText
  const post = resolvePaymentPostAction(settings, paymentGate, block, context)
  const isTestBlock = paymentGate.mode === 'test'
  const paymentTestGuide = isTestBlock ? renderPaymentTestGuide(paymentGate.gateway) : ''
  // Personalización de diseño del checkout (todas con default = comportamiento actual).
  const showKicker = settings.paymentShowGatewayName !== false
  const showSecure = settings.paymentShowSecureNote !== false
  const secureNote = cleanString(settings.paymentSecureNote) || PAYMENT_SECURE_NOTE_DEFAULT
  const showCountry = settings.paymentShowCountry !== false
  // Captura de identidad del comprador (correo/telefono) para poder LIGAR el pago a
  // un contacto y asi disparar el evento Purchase de Meta. CLIP y MercadoPago ya la
  // piden en su propio SDK/checkout hospedado, asi que el bloque compartido solo se
  // inyecta para Stripe/Conekta. El comprador debe dar al menos uno (correo o telefono).
  const paymentGateway = cleanString(paymentGate.gateway)
  const providerCollectsIdentity = paymentGateway === 'clip' || paymentGateway === 'mercadopago' || paymentGateway === 'rebill'
  const collectEmail = isSubscriptionCheckout ? true : settings.paymentCollectEmail !== false
  const collectPhone = isSubscriptionCheckout ? true : settings.paymentCollectPhone !== false
  const showIdentityFields = (isSubscriptionCheckout || !providerCollectsIdentity) && (collectEmail || collectPhone)
  const identityInputStyle = 'width:100%;box-sizing:border-box;border:1px solid color-mix(in srgb, var(--rstk-muted, CanvasText) 28%, transparent);border-radius:var(--rstk-radius, 12px);background:var(--rstk-input-bg, color-mix(in srgb, var(--rstk-surface, Canvas) 86%, transparent));color:var(--rstk-checkout-field-text, var(--rstk-block-text, var(--rstk-ink, CanvasText)));padding:12px 13px;font:inherit;min-width:0;'
  const checkoutAlign = blockHorizontalAlign(settings, 'paymentTextAlign', 'left')
  // Se permite '/' para colores CSS modernos (p. ej. rgb(0 0 0 / 50%)) sin romper la
  // apariencia de la pasarela; el resto de caracteres peligrosos se siguen filtrando.
  const fieldTextColor = cleanString(settings.paymentFieldTextColor).replace(/[^a-zA-Z0-9#().,%\s/-]/g, '')
  // Ancho/posición del botón de pago: por defecto ancho completo (comportamiento actual).
  // buttonAlign 'full' o buttonWidth>0 lo controlan; con ancho parcial, buttonAlign
  // decide dónde se ancla dentro del checkout.
  const payButtonAlign = blockButtonAlign(settings, 'full')
  const payButtonWidthPct = Number(settings.buttonWidth)
  const payWidth = payButtonAlign === 'full' || !(payButtonWidthPct > 0) ? '100%' : `${Math.min(100, Math.max(10, Math.round(payButtonWidthPct)))}%`
  const payJustify = payWidth === '100%' ? 'stretch' : (payButtonAlign === 'left' ? 'start' : payButtonAlign === 'right' ? 'end' : 'center')
  const checkoutStyle = `--rstk-checkout-align:${checkoutAlign};--rstk-checkout-pay-width:${payWidth};--rstk-checkout-pay-justify:${payJustify}${fieldTextColor ? `;--rstk-checkout-field-text:${fieldTextColor}` : ''}`

  // Shell del checkout EMBEBIDO inline. El runtime del sitio publicado llama a
  // /api/sites/public/checkout/init, monta el SDK del proveedor dentro de
  // [data-rstk-checkout-fields] y, al confirmar paid, ejecuta la acción posterior
  // (data-post-*). Los campos de tarjeta viven en iframes cifrados del proveedor.
  return `
    <section class="rstk-payment-block rstk-payment-${escapeHtml(layout)}"
      style="${escapeHtml(checkoutStyle)}"
      data-rstk-payment-block
      data-rstk-checkout
      data-site-id="${escapeHtml(siteId)}"
      data-payment-page-id="${escapeHtml(pageId)}"
      data-payment-block-id="${escapeHtml(block.id || '')}"
      data-provider="${escapeHtml(paymentGate.gateway)}"
      data-billing-type="${isSubscriptionCheckout ? 'subscription' : 'single'}"
      data-subscription-interval-type="${escapeHtml(paymentGate.subscription?.intervalType || 'monthly')}"
      data-subscription-interval-count="${escapeHtml(String(paymentGate.subscription?.intervalCount || 1))}"
      data-amount="${escapeHtml(String(paymentGate.amount))}"
      data-currency="${escapeHtml(paymentGate.currency)}"
      data-button-text="${escapeHtml(buttonLabel)}"
      data-post-action="${escapeHtml(post.action)}"
      data-post-url="${escapeHtml(post.url)}"
      data-post-message="${escapeHtml(post.message)}"
      data-show-country="${showCountry ? 'true' : 'false'}"
      data-collect-email="${showIdentityFields && collectEmail ? 'true' : 'false'}"
      data-collect-phone="${showIdentityFields && collectPhone ? 'true' : 'false'}"
      ${isTestBlock ? 'data-test-mode="true"' : ''}>
      <div class="rstk-checkout-card">
        <div class="rstk-checkout-inner">
          <div class="rstk-checkout-head">
            ${showKicker ? `<span class="rstk-payment-kicker">${escapeHtml(getPaymentGatewayLabel(paymentGate.gateway))}</span>` : ''}
            <strong class="rstk-checkout-title">${escapeHtml(productName)}</strong>
            ${description ? `<p class="rstk-checkout-desc">${escapeHtml(description)}</p>` : ''}
            <span class="rstk-checkout-amount">${escapeHtml(amountDisplayText)}</span>
          </div>
          ${isTestBlock ? '<p class="rstk-checkout-testbadge">Modo prueba · no es un cobro real</p>' : ''}
          <div class="rstk-checkout-body" data-rstk-checkout-body>
            <div class="rstk-checkout-loading" data-rstk-checkout-loading>
              <span class="rstk-checkout-spinner" aria-hidden="true"></span>
              <span>Cargando pago seguro…</span>
            </div>
            ${showIdentityFields ? `<div class="rstk-checkout-identity" data-rstk-checkout-identity style="display:grid;gap:10px;margin-bottom:12px">
              ${collectEmail ? `<input type="email" inputmode="email" autocomplete="email" data-rstk-identity-email placeholder="Correo electrónico" aria-label="Correo electrónico" style="${identityInputStyle}" />` : ''}
              ${collectPhone ? `<input type="tel" inputmode="tel" autocomplete="tel" data-rstk-identity-phone placeholder="Teléfono" aria-label="Teléfono" style="${identityInputStyle}" />` : ''}
              <p class="rstk-checkout-message" data-rstk-identity-error role="alert" hidden style="margin:0" data-kind="error">Escribe tu correo o teléfono para continuar.</p>
            </div>` : ''}
            <div class="rstk-checkout-fields" data-rstk-checkout-fields hidden></div>
            <div class="rstk-checkout-installments" data-rstk-checkout-installments hidden></div>
            <button type="button" class="rstk-button-link rstk-checkout-pay" data-rstk-checkout-pay hidden>
              ${renderSubmitButtonContent(`${buttonLabel} · ${amountDisplayText}`, '', settings, { labelAttr: ' data-rstk-checkout-pay-label' })}
            </button>
            <p class="rstk-checkout-message" data-rstk-checkout-message role="status" hidden></p>
            ${paymentTestGuide}
            ${showSecure ? `<p class="rstk-checkout-secure">${escapeHtml(secureNote)}</p>` : ''}
          </div>
          <div class="rstk-checkout-success" data-rstk-checkout-success hidden></div>
        </div>
      </div>
    </section>
  `
}

function renderContentBlock(block, context = {}) {
  const content = escapeHtml(block.content)
  const settings = block.settings || {}

  if (block.blockType === 'header_panel' || block.blockType === 'footer_panel') {
    const isHeader = block.blockType === 'header_panel'
    // El menú del panel apunta a páginas reales del sitio: resolvePanelNavLinks
    // descarta enlaces a páginas inexistentes y usa el título vivo de la página
    // como label por defecto; el href sale de buildPageHref (respeta el modo de
    // enlace path/query del sitio).
    const links = resolvePanelNavLinks(settings.panelLinks, normalizeSitePages(context.site))
    // El footer es multilínea en el editor: sus saltos de línea se publican como
    // <br> (igual que headline/subheading/text). El header es de una sola línea.
    const copy = isHeader
      ? (content || escapeHtml(block.label || 'Tu marca'))
      : (content.replace(/\n/g, '<br>') || 'Tu información está protegida.')
    return `
      <div class="rstk-site-panel ${isHeader ? 'rstk-site-panel-header' : 'rstk-site-panel-footer'}">
        ${isHeader ? `<strong class="rstk-site-panel-copy">${copy}</strong>` : `<p class="rstk-site-panel-copy">${copy}</p>`}
        ${links.length ? `
          <nav class="rstk-site-panel-links" aria-label="${isHeader ? 'Enlaces superiores' : 'Enlaces inferiores'}">
            ${links.map(link => {
              const href = link.pageId ? buildPageHref(link.pageId, context) : safeHref(link.url, '#')
              return `<a href="${escapeHtml(href)}">${escapeHtml(link.label)}</a>`
            }).join('')}
          </nav>
        ` : ''}
      </div>
    `
  }

  if (block.blockType === 'social_profile') {
    return renderSocialProfileBlock(block, context)
  }

  if (block.blockType === 'headline' || block.blockType === 'title') {
    // Paridad content #5: los saltos de línea del editor (contenteditable) se
    // publican como <br>, igual que el bloque de texto.
    return `<h1 class="rstk-headline">${content.replace(/\n/g, '<br>') || escapeHtml(block.label)}</h1>`
  }

  if (block.blockType === 'section') {
    return `
      <section class="rstk-section-break">
        <h2>${content || escapeHtml(block.label || 'Nueva sección')}</h2>
        ${settings.subtitle ? `<p>${escapeHtml(settings.subtitle)}</p>` : ''}
      </section>
    `
  }

  if (block.blockType === 'subheading' || block.blockType === 'subtitle' || block.blockType === 'description') {
    // Paridad content #5: saltos de línea del editor -> <br> (como el bloque texto).
    return `<p class="rstk-subheading">${content.replace(/\n/g, '<br>') || escapeHtml(block.label)}</p>`
  }

  if (block.blockType === 'hero') {
    const buttonUrl = resolveButtonHref(settings, context)
    const buttonActionAttrs = renderButtonActionAttributes(settings)
    const buttonContent = renderSubmitButtonContent(settings.buttonText, settings.buttonSubtitle, settings)
    return `
      <section class="rstk-hero">
        ${settings.kicker ? `<p class="rstk-kicker">${escapeHtml(settings.kicker)}</p>` : ''}
        <h1 class="rstk-headline">${content || escapeHtml(block.label)}</h1>
        ${settings.subtitle ? `<p class="rstk-subheading">${escapeHtml(settings.subtitle)}</p>` : ''}
        ${settings.buttonText ? `<a class="rstk-button-link" href="${escapeHtml(buttonUrl)}"${buttonActionAttrs}>${buttonContent}</a>` : ''}
      </section>
    `
  }

  if (block.blockType === 'image') {
    const imageUrl = safePublicMediaUrl(settings.mediaUrl || block.content, 'image')
    return imageUrl
      ? `<figure class="rstk-media"><img src="${escapeHtml(imageUrl)}" alt="${escapeHtml(block.label || 'Imagen')}" loading="lazy"></figure>`
      : `<div class="rstk-media rstk-media-empty rstk-media-empty-mock"><span class="rstk-media-empty-icon" aria-hidden="true">${RSTK_ICONS.image}</span><span>Agrega una imagen</span></div>`
  }

  if (block.blockType === 'video') {
    const rawVideoUrl = settings.mediaUrl || block.content
    const directVideoUrl = isDirectVideoUrl(rawVideoUrl) ? safePublicMediaUrl(rawVideoUrl, 'video') : ''
    const videoUrl = directVideoUrl ? '' : normalizeVideoEmbedUrl(rawVideoUrl)
    const liveStreamAsset = directVideoUrl ? getLiveStreamAssetForStorageVideo(rawVideoUrl, context) : null
    const liveStream = getMediaAssetStreamMetadata(liveStreamAsset)
    const noTrackStreamMarkup = videoUrl ? renderNoTrackBunnyStreamBlock(videoUrl, block, settings, context) : ''
    const embedVideoUrl = context.noTrack ? appendNoTrackParam(videoUrl) : videoUrl
    const storageAssetForStreamVideo = embedVideoUrl ? getStorageAssetForStreamVideoUrl(embedVideoUrl, context) : null
    const storageStream = getMediaAssetStreamMetadata(storageAssetForStreamVideo)

    if (directVideoUrl) {
      if (liveStreamAsset?.publicUrl) {
        return renderStorageBackedBunnyStreamVideo(liveStreamAsset, block, settings, context, liveStream)
      }

      return renderVideoPlayer(directVideoUrl, block, settings, {
        noTrack: false,
        tracking: {
          enabled: !context.noTrack,
          provider: 'html5_video'
        },
        context
      })
    }

    if (noTrackStreamMarkup) return noTrackStreamMarkup

    if (embedVideoUrl) {
      if (getBunnyStreamVideoIdFromUrl(embedVideoUrl)) {
        if (storageAssetForStreamVideo?.publicUrl) {
          return renderStorageBackedBunnyStreamVideo(storageAssetForStreamVideo, block, settings, context, storageStream)
        }

        return renderBunnyStreamIframe(embedVideoUrl, block, {
          enabled: !context.noTrack,
          asset: storageAssetForStreamVideo,
          stream: getStreamMetadataForVideoUrl(embedVideoUrl, context)
        }, settings, context)
      }

      const iframeOrientation = normalizeVideoOrientation(settings)
      return `<div class="rstk-video rstk-video-embed-frame rstk-video-${iframeOrientation} ${getVideoPortraitWidthModeClass(getVideoPortraitWidthMode(settings))}" style="${renderVideoFrameStyle(settings, iframeOrientation)}"><iframe src="${escapeHtml(embedVideoUrl)}" loading="lazy" allow="${escapeHtml(DEFAULT_EMBED_ALLOW)}" allowfullscreen sandbox="allow-scripts allow-same-origin allow-forms allow-popups allow-presentation"></iframe></div>`
    }

    return `<div class="rstk-media rstk-media-empty rstk-media-empty-mock rstk-media-empty-video"><span class="rstk-play">${RSTK_ICONS.play}</span><span>Agrega la URL del video</span></div>`
  }

  if (block.blockType === 'countdown') {
    return renderCountdownBlock(block)
  }

  if (block.blockType === 'payment') {
    return renderPaymentBlock(block, context)
  }

  if (block.blockType === 'button') {
    const buttonUrl = resolveButtonHref(settings, context)
    const buttonActionAttrs = renderButtonActionAttributes(settings)
    return `<a class="rstk-button-link" href="${escapeHtml(buttonUrl)}"${buttonActionAttrs}>${renderSubmitButtonContent(settings.buttonText || block.content || block.label || 'Continuar', settings.buttonSubtitle, settings)}</a>`
  }

  if (block.blockType === 'benefits') {
    const items = getItems(settings)
    const heading = content || escapeHtml(block.label)
    return `
      <section class="rstk-section-list rstk-checklist">
        ${heading ? `<h2>${heading}</h2>` : ''}
        <ul class="rstk-check-list">
          ${items.map(item => {
            const tone = getItemTone(item)
            const icon = tone === 'con' ? RSTK_ICONS.cross : RSTK_ICONS.check
            const title = escapeHtml(stripToneMarker(item.title))
            const text = escapeHtml(stripToneMarker(item.text))
            return `
              <li class="rstk-check rstk-check-${tone}">
                <span class="rstk-check-icon" aria-hidden="true">${icon}</span>
                <span class="rstk-check-body">
                  ${title ? `<strong>${title}</strong>` : ''}
                  ${text ? `<span>${text}</span>` : ''}
                </span>
              </li>
            `
          }).join('')}
        </ul>
      </section>
    `
  }

  if (['testimonials', 'services', 'faq'].includes(block.blockType)) {
    const items = getItems(settings)
    // Guarda contra <h2></h2> vacío cuando no hay título ni nombre interno
    // (mismo patrón que benefits): evita reservar espacio por el gap del grid.
    const heading = content || escapeHtml(block.label)
    return `
      <section class="rstk-section-list">
        ${heading ? `<h2>${heading}</h2>` : ''}
        <div class="rstk-list-grid">
          ${items.map(item => `
            <article>
              ${item.title ? `<strong>${escapeHtml(item.title)}</strong>` : ''}
              ${item.text ? `<p>${escapeHtml(item.text)}</p>` : ''}
              ${item.author ? `<small>${escapeHtml(item.author)}</small>` : ''}
            </article>
          `).join('')}
        </div>
      </section>
    `
  }

  if (block.blockType === 'form_embed') {
    const isImportedForm = Boolean(
      cleanString(settings.formSiteId) || cleanString(settings.embeddedSiteId) || cleanString(settings.form_site_id)
    )
    const localEmbeddedTheme = isPlainObject(settings.embeddedTheme) ? { ...settings.embeddedTheme } : {}
    // Importado: descarta el borde transparente auto-inyectado para no pisar el marco del fuente.
    if (isImportedForm && localEmbeddedTheme.pageBorderColor === 'transparent') {
      delete localEmbeddedTheme.pageBorderWidth
      delete localEmbeddedTheme.pageBorderColor
    }
    // El borde default (EMBEDDED_FORM_DEFAULT_THEME) es SOLO para lienzos nuevos sin
    // fuente; un formulario importado conserva el marco real de su diseño guardado.
    // La cadena de merge vive en el contrato compartido: theme trae los valores (con
    // DEFAULT_THEME) y sourceTheme es la cadena cruda para la explicitud del frame.
    const { theme: embeddedTheme, sourceTheme: embeddedSourceRawTheme } = buildEmbeddedFormTheme({
      hostTheme: context.site?.theme,
      sourceFormTheme: localEmbeddedTheme,
      isImportedForm
    })
    const embeddedSiteForCopy = { ...(context.site || {}), siteType: settings.embeddedSiteType || 'standard_form', theme: embeddedTheme }
    const embeddedSubmitText = cleanString(embeddedTheme.submitText) || context.submitText
    const embeddedSubmitSubtitle = cleanString(embeddedTheme.submitSubtitle || embeddedTheme.submitSubtext || embeddedTheme.formButtonSubtitle) || context.submitSubtitle
    const embeddedContinueText = cleanString(embeddedTheme.continueText) || context.continueText
    const embeddedNextText = cleanString(embeddedTheme.nextText) || context.nextText
    const embeddedPages = normalizeEmbeddedFormPages(settings.embeddedPages)
    const embeddedPageIds = new Set(embeddedPages.map(page => page.id))
    const embeddedItems = (Array.isArray(settings.embeddedBlocks) ? settings.embeddedBlocks : [])
      .filter(item => {
        const rawPageId = cleanString(item?.settings?.pageId)
        return EMBEDDED_FORM_BLOCK_TYPES.has(item?.blockType) && (!rawPageId || embeddedPageIds.has(rawPageId))
      })
    const fields = collectFieldBlocks(embeddedItems)
    const hasEmbeddedPaymentBlock = Boolean(findEnabledPaymentBlockContext(embeddedItems, embeddedSiteForCopy))
    const hasEmbeddedPages = embeddedPages.length > 1
    const firstEmbeddedPageId = embeddedPages[0]?.id || DEFAULT_FUNNEL_PAGE_ID
    const lastEmbeddedPageId = embeddedPages[embeddedPages.length - 1]?.id || firstEmbeddedPageId
    const firstButtonCopy = getFormPageButtonCopy({
      site: embeddedSiteForCopy,
      pages: embeddedPages,
      pageId: firstEmbeddedPageId,
      submitText: embeddedSubmitText,
      submitSubtitle: embeddedSubmitSubtitle,
      continueText: embeddedContinueText,
      nextText: embeddedNextText
    })
    const finalButtonCopy = getFormPageButtonCopy({
      site: embeddedSiteForCopy,
      pages: embeddedPages,
      pageId: hasEmbeddedPages ? lastEmbeddedPageId : firstEmbeddedPageId,
      submitText: embeddedSubmitText,
      submitSubtitle: embeddedSubmitSubtitle,
      continueText: embeddedContinueText,
      nextText: embeddedNextText
    })
    const submitButtonContent = renderSubmitButtonContent(finalButtonCopy.label, finalButtonCopy.subtitle, settings)
    const nextButtonContent = normalizeButtonIconName(settings.buttonIcon)
      ? renderSubmitButtonContent(firstButtonCopy.label, '', settings)
      : escapeHtml(firstButtonCopy.label)
    const embeddedRenderContext = { ...context, site: embeddedSiteForCopy }
    const renderEmbeddedItem = (item, pageId) => {
      if (FIELD_BLOCK_TYPES.has(item.blockType)) {
        return wrapRenderedBlock(item, renderFieldBlock(item, false, pageId || getBlockPageId(item, embeddedPages), embeddedRenderContext), embeddedRenderContext)
      }

      return wrapRenderedBlock(item, renderContentBlock(item, embeddedRenderContext), embeddedRenderContext)
    }
    const renderEmbeddedItems = () => {
      if (!embeddedItems.length) return '<p class="rstk-help">Agrega campos o contenido al formulario.</p>'
      if (!hasEmbeddedPages) {
        return embeddedItems.map(item => renderEmbeddedItem(item, getBlockPageId(item, embeddedPages))).join('\n')
      }
      return `
        <div class="rstk-embedded-pages" data-embedded-form-pages>
          ${embeddedPages.map((page, index) => {
            const pageItems = getEmbeddedFormPageFields(embeddedItems, embeddedPages, page.id)
            const buttonCopy = getFormPageButtonCopy({
              site: embeddedSiteForCopy,
              pages: embeddedPages,
              pageId: page.id,
              submitText: embeddedSubmitText,
              submitSubtitle: embeddedSubmitSubtitle,
              continueText: embeddedContinueText,
              nextText: embeddedNextText
            })
            return `
              <div data-embedded-page-content="${escapeHtml(page.id)}"${index === 0 ? '' : ' hidden'} data-next-label="${escapeHtml(buttonCopy.label)}" data-submit-label="${escapeHtml(buttonCopy.label)}" data-submit-subtitle="${escapeHtml(buttonCopy.subtitle)}">
                ${pageItems.length
                  ? pageItems.map(item => renderEmbeddedItem(item, page.id)).join('\n')
                  : `<p class="rstk-help">Esta página no tiene contenido.</p>`}
              </div>
            `
          }).join('\n')}
        </div>
      `
    }
    // El frame se tematiza con la cadena CRUDA: así un fondo no elegido por el
    // usuario conserva la paleta del template también dentro del embed (embeds #2).
    const embeddedSourceTheme = buildEmbeddedFormSourceTheme({ ...embeddedSiteForCopy, theme: embeddedSourceRawTheme }, context.formStyleContext)
    const embeddedStyle = embeddedSourceTheme.style.replace(/\s+/g, ' ').trim()
    const embeddedThemeClass = [
      'rstk-embedded-form-theme',
      'rstk-embedded-form-source-frame',
      settings.embeddedFullWidth === true ? 'rstkEmbeddedFormStretch' : '',
      embeddedSourceTheme.bodyClass,
      `rstk-choice-${normalizeFormChoiceStyle(embeddedTheme.formChoiceStyle)}`,
      `rstk-select-${normalizeFormSelectStyle(embeddedTheme.formSelectStyle)}`,
      `rstk-input-${normalizeFormInputStyle(embeddedTheme.formInputStyle)}`
    ].filter(Boolean).join(' ')
    // Pantallas de resultado del formulario fuente (Calificado / No calificado),
    // que en standalone son páginas propias (page-2 / page-3). En el embed se
    // renderizan inline ocultas y el runtime las muestra al enviar según califique
    // (un landing no puede navegar a esas páginas porque viven inlined aquí).
    const embeddedResultItems = (pageId, defaultBlocks) => {
      const own = (Array.isArray(settings.embeddedBlocks) ? settings.embeddedBlocks : [])
        .filter(item => cleanString(item?.settings?.pageId || item?.settings?.page_id) === pageId && EMBEDDED_FORM_CONTENT_BLOCK_TYPES.has(item?.blockType))
        .sort((a, b) => (Number(a?.sortOrder) || 0) - (Number(b?.sortOrder) || 0))
      return own.length ? own : defaultBlocks(settings.embeddedSiteId || '')
    }
    const renderEmbeddedResult = (status, pageId, defaultBlocks) => {
      const items = embeddedResultItems(pageId, defaultBlocks)
      if (!items.length) return ''
      return `
          <div class="rstk-embedded-form-result" data-embedded-form-result="${escapeHtml(status)}" hidden>
            ${items.map(item => renderEmbeddedItem(item, pageId)).join('\n')}
          </div>`
    }
    const embeddedSection = `
      <section class="rstk-embedded-form" id="form">
        ${renderEmbeddedItems()}
        ${fields.length || hasEmbeddedPaymentBlock ? `
          <div class="rstk-actions rstk-embed-actions"${context.revealFormActionControlled ? ' data-rstk-form-action-area data-rstk-video-action-hidden="true" aria-hidden="true"' : ''}>
            ${hasEmbeddedPages ? `<button type="button" class="rstk-secondary" data-embedded-back hidden>${escapeHtml(context.backText || 'Anterior')}</button>` : ''}
            ${hasEmbeddedPages ? `<button type="button" data-embedded-next>${nextButtonContent}</button>` : ''}
            <button type="submit" data-submit${hasEmbeddedPages ? ' hidden' : ''}>${submitButtonContent}</button>
          </div>
          <p class="rstk-submit-message" data-message role="status"></p>
          ${renderEmbeddedResult('qualified', FORM_THANK_YOU_PAGE_ID, getDefaultFormThankYouBlocks)}
          ${renderEmbeddedResult('disqualified', FORM_DISQUALIFIED_PAGE_ID, getDefaultFormDisqualifiedBlocks)}
        ` : ''}
      </section>
    `
    // El perfil de red social ya es un bloque embebible normal (se renderiza dentro
    // de renderEmbeddedItems). El "chrome" por template queda solo como respaldo para
    // formularios sociales que no traen un bloque de perfil explícito, evitando doble.
    const embeddedHasSocialProfile = embeddedItems.some(item => item?.blockType === 'social_profile')
    const embeddedSourceChrome = embeddedHasSocialProfile ? '' : renderEmbeddedFormSourceChrome(embeddedSiteForCopy)
    const embeddedFrame = `
      <div class="${embeddedThemeClass}" style="${escapeHtml(embeddedStyle)}">
        ${embeddedSourceTheme.pageVideo ? renderBackgroundVideoElement(embeddedSourceTheme.pageVideo, 'rstk-bg-video') : ''}
        <div class="rstk-page">
          <div class="rstk-shell">
            ${embeddedSourceChrome}
            ${embeddedSection}
          </div>
        </div>
      </div>
    `
    return embeddedStyle
      ? embeddedFrame
      : embeddedSection
  }

  if (block.blockType === 'cta') {
    const buttonUrl = resolveButtonHref(settings, context)
    const buttonActionAttrs = renderButtonActionAttributes(settings)
    const buttonContent = renderSubmitButtonContent(settings.buttonText, settings.buttonSubtitle, settings)
    return `
      <section class="rstk-cta">
        <h2>${content || escapeHtml(block.label)}</h2>
        ${settings.subtitle ? `<p>${escapeHtml(settings.subtitle)}</p>` : ''}
        ${settings.buttonText ? `<a class="rstk-button-link" href="${escapeHtml(buttonUrl)}"${buttonActionAttrs}>${buttonContent}</a>` : ''}
      </section>
    `
  }

  if (block.blockType === 'calendar_embed') {
    const calendarSlug = cleanString(settings.calendarSlug || settings.calendar_slug || block.content)
    if (!calendarSlug) {
      return `<div class="rstk-embed rstk-embed-empty">Selecciona un calendario para embeber</div>`
    }

    const calendarName = cleanString(settings.calendarName || settings.calendar_name || block.label || 'Calendario')
    const calendarCompletionRedirect = getCalendarEmbedCompletionRedirect(block, context)
    // El SITIO es master: si la pagina dueña del calendario configuro un evento "al agendar"
    // (con Meta del sitio encendido), ese evento overridea el del calendario embebido. Sin
    // override, el calendario usa su propio evento (fallback, no mudo). No se propaga en preview.
    const calendarMetaOverride = resolveCalendarMetaOverride(context, block)
    const calendarBasePath = context.preview
      ? `/api/sites/public/calendar-preview/${encodeURIComponent(calendarSlug)}?test=1`
      : `/calendar/${encodeURIComponent(calendarSlug)}?test=1`
    const baseCalendarSrc = appendCalendarEmbedParams(calendarBasePath, settings, {
      preview: context.preview,
      bookingBridge: Boolean(calendarCompletionRedirect),
      ...buildCalendarEmbedMetaParams(calendarMetaOverride)
    })
    const calendarSrc = context.noTrack ? appendNoTrackParam(baseCalendarSrc) : baseCalendarSrc
    const calendarRedirectAttr = calendarCompletionRedirect ? ` data-rstk-calendar-redirect="${escapeHtml(calendarCompletionRedirect)}"` : ''
    return `<iframe class="rstk-embed rstk-calendar-embed" src="${escapeHtml(calendarSrc)}" title="${escapeHtml(calendarName)}"${calendarRedirectAttr} loading="lazy" scrolling="no" sandbox="allow-scripts allow-same-origin allow-forms allow-popups"></iframe>`
  }

  if (block.blockType === 'embed') {
    const embed = resolveEmbedContent(block.content)
    if (embed.kind === 'empty') {
      return `<div class="rstk-embed rstk-embed-empty">Pega una URL, iframe o código embed</div>`
    }

    const heightStyle = embed.height ? ` style="min-height:${embed.height}px"` : ''
    if (embed.kind === 'url') {
      const embedSrc = context.noTrack ? appendNoTrackParam(embed.src) : embed.src
      return `<iframe class="rstk-embed" src="${escapeHtml(embedSrc)}" title="${escapeHtml(embed.title)}" loading="lazy" referrerpolicy="no-referrer-when-downgrade" sandbox="${EMBED_SANDBOX_URL}" allow="${escapeHtml(embed.allow || DEFAULT_EMBED_ALLOW)}" allowfullscreen${heightStyle}></iframe>`
    }

    return `<iframe class="rstk-embed rstk-embed-code" srcdoc="${escapeHtml(embed.srcDoc)}" title="${escapeHtml(embed.title)}" loading="lazy" referrerpolicy="no-referrer-when-downgrade" sandbox="${EMBED_SANDBOX_HTML}" allow="${escapeHtml(embed.allow || DEFAULT_EMBED_ALLOW)}"${heightStyle}></iframe>`
  }

  return `<div class="rstk-text">${content.replace(/\n/g, '<br>')}</div>`
}

const supportedNativeFieldValidations = new Set(['email', 'phone', 'number', 'currency', 'date', 'url'])

function getNativeFieldValidation(block = {}) {
  const settings = block.settings || {}
  const systemFieldKey = getNativeSystemFieldKey(block)
  if (systemFieldKey === 'email') return 'email'
  if (systemFieldKey === 'phone') return 'phone'
  if (block.blockType === 'email') return 'email'
  if (block.blockType === 'phone') return 'phone'
  const explicit = cleanString(settings.validation || settings.fieldValidation || settings.field_validation).toLowerCase()
  if (supportedNativeFieldValidations.has(explicit)) return explicit
  if (block.blockType === 'number') return 'number'
  if (block.blockType === 'currency') return 'currency'
  if (block.blockType === 'date') return 'date'
  return ''
}

// Serializa las reglas nativas del contrato compartido en atributos HTML, en
// orden fijo (inputmode, min, max, step) para paridad byte-a-byte con el canvas.
function nativeFieldRulesAttrString(block) {
  const attrs = getNativeFieldRulesAttributes(block)
  return ['inputmode', 'min', 'max', 'step']
    .filter(key => attrs[key] !== undefined && attrs[key] !== null)
    .map(key => ` ${key}="${escapeHtml(String(attrs[key]))}"`)
    .join('')
}

function renderFieldInput(block, context = {}) {
  const id = escapeHtml(block.id)
  const placeholder = escapeHtml(block.placeholder)
  const required = block.required ? 'required' : ''
  const options = getBlockOptions(block)
  const settings = block.settings || {}
  const validation = getNativeFieldValidation(block)

  if (block.blockType === 'paragraph') {
    return `<textarea id="${id}" name="${id}" rows="5" placeholder="${placeholder}" ${required}></textarea>`
  }

  if (block.blockType === 'currency') {
    return `<input id="${id}" name="${id}" type="number"${nativeFieldRulesAttrString(block)} placeholder="${placeholder || '0.00'}" ${required}>`
  }

  if (block.blockType === 'number') {
    return `<input id="${id}" name="${id}" type="number"${nativeFieldRulesAttrString(block)} placeholder="${placeholder}" ${required}>`
  }

  if (block.blockType === 'email') {
    return `<input id="${id}" name="${id}" type="email" inputmode="email" autocomplete="email" placeholder="${placeholder}" ${required}>`
  }

  if (block.blockType === 'phone') {
    const selectorEnabled = isPhoneCountrySelectorEnabled(block)
    const defaultCountryCode = cleanString(
      settings.defaultCountryCode ||
      settings.countryCode ||
      context.phoneLocale?.countryCode ||
      'MX'
    ).toUpperCase()
    // El selector de país siempre se renderiza para poder anteponer la lada al
    // número (lo que el contacto envía siempre llega normalizado a E.164).
    // Cuando el autor desactiva "Mostrar país y lada" el <select> queda oculto y
    // la lada se aplica de forma automática a partir de la región detectada del
    // visitante (con la lada de la cuenta como respaldo).
    const hiddenAttr = selectorEnabled ? '' : ' data-phone-country-hidden'
    const selectHiddenAttrs = selectorEnabled ? '' : ' aria-hidden="true" tabindex="-1"'
    return `
      <div class="rstk-phone-input" data-phone-country-field${hiddenAttr}>
        <select id="${id}__country" name="${id}__country" data-phone-country-select aria-label="País y lada"${selectHiddenAttrs}>
          ${renderPhoneCountryOptions(defaultCountryCode)}
        </select>
        <input id="${id}" name="${id}" type="tel" inputmode="tel" autocomplete="tel-national" placeholder="${placeholder || 'Número'}" data-phone-number-input ${required}>
      </div>
    `
  }

  if (block.blockType === 'date') {
    return `<input id="${id}" name="${id}" type="date"${nativeFieldRulesAttrString(block)} placeholder="${placeholder}" ${required}>`
  }

  if (validation === 'email') {
    return `<input id="${id}" name="${id}" type="email" inputmode="email" autocomplete="email" placeholder="${placeholder}" ${required}>`
  }

  if (validation === 'phone') {
    return `<input id="${id}" name="${id}" type="tel" inputmode="tel" autocomplete="tel" placeholder="${placeholder}" ${required}>`
  }

  if (block.blockType === 'dropdown') {
    return `
      <select id="${id}" name="${id}" ${required}>
        <option value="">${placeholder || 'Selecciona una opción'}</option>
        ${options.map(option => `<option value="${escapeHtml(option.value)}" ${optionRuleAttributes(option)}>${escapeHtml(option.label)}</option>`).join('')}
      </select>
    `
  }

  if (block.blockType === 'radio') {
    return `
      <div class="rstk-options">
        ${options.map((option, index) => `
          <label class="rstk-option">
            <input type="radio" name="${id}" value="${escapeHtml(option.value)}" ${required && index === 0 ? 'required' : ''} ${optionRuleAttributes(option)}>
            <span>${escapeHtml(option.label)}</span>
          </label>
        `).join('')}
      </div>
    `
  }

  if (block.blockType === 'checkboxes') {
    return `
      <div class="rstk-options">
        ${options.map(option => `
          <label class="rstk-option">
            <input type="checkbox" name="${id}" value="${escapeHtml(option.value)}" data-checkbox-group="${id}" ${optionRuleAttributes(option)}>
            <span>${escapeHtml(option.label)}</span>
          </label>
        `).join('')}
      </div>
    `
  }

  if (validation === 'url') {
    return `<input id="${id}" name="${id}" type="url" inputmode="url" placeholder="${placeholder}" ${required}>`
  }

  return `<input id="${id}" name="${id}" type="text" placeholder="${placeholder}" ${required}>`
}

function renderFieldBlock(block, _interactive = false, pageId = '', context = {}) {
  const label = escapeHtml(block.label || 'Pregunta')
  const required = block.required ? '<span class="rstk-required">*</span>' : ''
  const systemFieldKey = getNativeSystemFieldKey(block)

  return `
    <section class="rstk-field${getFieldOwnStyleClass(block)}" data-block-id="${escapeHtml(block.id)}" data-page-id="${escapeHtml(pageId)}" data-system-field-key="${escapeHtml(systemFieldKey)}" data-required="${block.required ? 'true' : 'false'}" data-field-type="${escapeHtml(block.blockType)}" data-validation="${escapeHtml(getNativeFieldValidation(block))}">
      <label for="${escapeHtml(block.id)}">${label}${required}</label>
      ${block.content ? `<p class="rstk-help">${escapeHtml(block.content)}</p>` : ''}
      ${renderFieldInput(block, context)}
      ${['dropdown', 'radio', 'checkboxes'].includes(block.blockType) ? '<p class="rstk-disqualify-notice" data-disqualify-notice hidden></p>' : ''}
      <p class="rstk-error" data-field-error aria-live="polite" hidden>Esta respuesta es requerida.</p>
    </section>
  `
}

function getBrand(site, template) {
  const theme = (site && site.theme) || {}
  const name = cleanString(theme.brandName) || cleanString(site && site.title) || cleanString(site && site.name) || 'Tu marca'
  const subtitleDefault = template.chrome === 'instagram' ? 'Publicación pagada' : 'Patrocinado'
  const subtitle = cleanString(theme.brandSubtitle) || subtitleDefault
  const avatarUrl = safeUrl(theme.brandAvatar)
  const followers = cleanString(theme.followers || theme.followersCount || theme.followerCount)
  const verified = theme.brandVerified === undefined ? true : normalizeBoolean(theme.brandVerified) === 1
  const handle = (slugify(name) || 'marca').replace(/-/g, '')
  const initial = (name.trim()[0] || 'R').toUpperCase()
  return { name, subtitle, avatarUrl, followers, verified, handle, initial }
}

function renderAvatar(brand) {
  if (brand.avatarUrl) {
    return `<span class="rstk-avatar"><img src="${escapeHtml(brand.avatarUrl)}" alt="${escapeHtml(brand.name)}"></span>`
  }
  return `<span class="rstk-avatar">${escapeHtml(brand.initial)}</span>`
}

function getSocialPlatformIcon(platform) {
  if (platform === 'tiktok') return RSTK_ICONS.music
  if (platform === 'threads') return '@'
  return ''
}

function resolveSocialProfileBlockData(block, context = {}) {
  const settings = block.settings || {}
  const siteTemplate = resolveTemplate(context.site)
  const fallbackPlatform = isSocialTemplate(siteTemplate.id) ? siteTemplate.id : 'facebook'
  const platform = normalizeSocialPlatform(settings.platform || settings.socialSourcePlatform, fallbackPlatform)
  const template = SITE_TEMPLATES[platform] || siteTemplate
  const siteBrand = getBrand(context.site || {}, template)
  const name = cleanString(settings.brandName) || siteBrand.name
  const subtitleDefault = platform === 'instagram' ? 'Publicación pagada' : 'Patrocinado'
  const subtitle = cleanString(settings.brandSubtitle) || siteBrand.subtitle || subtitleDefault
  const followers = cleanString(settings.followers || settings.followersCount || settings.followerCount) || siteBrand.followers
  const avatarUrl = safeUrl(settings.brandAvatar) || siteBrand.avatarUrl
  const verified = settings.brandVerified === undefined ? siteBrand.verified : normalizeBoolean(settings.brandVerified) === 1
  const initial = (name.trim()[0] || 'R').toUpperCase()
  const brand = {
    name,
    subtitle,
    followers,
    avatarUrl,
    verified,
    initial
  }
  const secondary = followers ? `${escapeHtml(followers)} seguidores` : escapeHtml(subtitle)
  const platformLabel = platform === 'facebook' ? 'Facebook' : platform === 'instagram' ? 'Instagram' : platform === 'threads' ? 'Threads' : 'TikTok'

  return { platform, platformLabel, brand, secondary }
}

function renderSocialProfileBlock(block, context = {}) {
  const { platform, platformLabel, brand, secondary } = resolveSocialProfileBlockData(block, context)

  return `
    <section class="rstk-chrome rstk-social-profile rstk-social-profile-block rstk-social-profile-${platform}" aria-label="Perfil de ${platformLabel}">
      <div class="rstk-social-image">
        ${renderAvatar(brand)}
        <span class="rstk-social-platform rstk-social-platform-${platform}" aria-hidden="true">${getSocialPlatformIcon(platform)}</span>
      </div>
      <div class="rstk-social-details">
        <div class="rstk-social-name">${escapeHtml(brand.name)}${brand.verified ? RSTK_ICONS.verified : ''}</div>
        <div class="rstk-social-followers">${secondary}</div>
      </div>
    </section>
  `
}

function renderEmbeddedFormSourceChrome(site = {}) {
  const template = resolveTemplate(site)
  if (!template || template.chrome === 'none') return ''

  const platform = normalizeSocialPlatform(template.chrome, 'facebook')
  const brand = getBrand(site, template)
  const secondary = brand.followers ? `${escapeHtml(brand.followers)} seguidores` : escapeHtml(brand.subtitle)
  const platformLabel = platform === 'facebook' ? 'Facebook' : platform === 'instagram' ? 'Instagram' : platform === 'threads' ? 'Threads' : 'TikTok'

  return `
    <section class="rstk-chrome rstk-social-profile rstk-social-profile-block rstk-embedded-form-source-chrome rstk-social-profile-${platform}" aria-label="Perfil de ${platformLabel}">
      <div class="rstk-social-image">
        ${renderAvatar(brand)}
        <span class="rstk-social-platform rstk-social-platform-${platform}" aria-hidden="true">${getSocialPlatformIcon(platform)}</span>
      </div>
      <div class="rstk-social-details">
        <div class="rstk-social-name">${escapeHtml(brand.name)}${brand.verified ? RSTK_ICONS.verified : ''}</div>
        <div class="rstk-social-followers">${secondary}</div>
      </div>
    </section>
  `
}

function renderLegalFooter(brand) {
  return `
    <p class="rstk-footer">
      <span class="rstk-lock" aria-hidden="true">${RSTK_ICONS.lock}</span>
      Tu información está protegida. ${escapeHtml(brand.name)} no la comparte con terceros.
    </p>
  `
}

const RSTK_GOOGLE_FONTS_HREF = 'https://fonts.googleapis.com/css2?family=Archivo:wght@400;500;600;700;800;900&family=Barlow:wght@400;500;600;700;800;900&family=Bebas+Neue&family=Inter:wght@400;500;600;700;800;900&family=Inter+Tight:wght@500;600;700;800;900&family=Lato:wght@400;700;900&family=Libre+Baskerville:wght@400;700&family=Manrope:wght@400;500;600;700;800&family=Merriweather:wght@400;700;900&family=Montserrat:wght@400;500;600;700;800;900&family=Nunito:wght@400;600;700;800;900&family=Open+Sans:wght@400;600;700;800&family=Oswald:wght@400;500;600;700&family=Playfair+Display:wght@400;600;700;800;900&family=Poppins:wght@400;500;600;700;800;900&family=Raleway:wght@400;500;600;700;800;900&family=Roboto:wght@400;500;700;900&family=Work+Sans:wght@400;500;600;700;800;900&display=swap'
const RSTK_SITE_FONT_FILE_PATH = '/api/sites/public/font-file'
const RSTK_FONT_CSS_CACHE_TTL_MS = 12 * 60 * 60 * 1000
const RSTK_FONT_FILE_CACHE_MAX_ITEMS = 220
let rstkFontCssCache = { css: '', expiresAt: 0 }
const rstkFontFileCache = new Map()

function rewriteSitesFontCss(css) {
  return String(css || '').replace(/url\((https:\/\/fonts\.gstatic\.com\/[^)]+)\)/g, (_match, url) => {
    return `url("${RSTK_SITE_FONT_FILE_PATH}?url=${encodeURIComponent(url)}")`
  })
}

const RSTK_FONT_FETCH_TIMEOUT_MS = 4000
const RSTK_FONT_CSS_FALLBACK = '/* Ristak Sites font stylesheet (fallback: origen de fuentes no disponible) */\n'

export async function getSitesFontCss() {
  const now = Date.now()
  if (rstkFontCssCache.css && rstkFontCssCache.expiresAt > now) return rstkFontCssCache.css

  // Timeout + fallback: si Google Fonts va lento o no responde, NO colgamos la
  // hoja (el <link> del sitio bloquearía el evento load de la página). Servimos un
  // stylesheet vacío — las font-family stacks ya traen fallback de sistema — y
  // reintentamos pronto.
  const controller = new AbortController()
  const timeout = setTimeout(() => controller.abort(), RSTK_FONT_FETCH_TIMEOUT_MS)
  try {
    const response = await fetch(RSTK_GOOGLE_FONTS_HREF, {
      headers: {
        'user-agent': 'Mozilla/5.0 Ristak Sites Font Loader'
      },
      signal: controller.signal
    })
    if (!response.ok) throw new Error(`Google Fonts respondió ${response.status}`)
    const css = `/* Ristak Sites font stylesheet */\n${rewriteSitesFontCss(await response.text())}`
    rstkFontCssCache = { css, expiresAt: now + RSTK_FONT_CSS_CACHE_TTL_MS }
    return css
  } catch (error) {
    logger.warn(`Fuentes de Sites no disponibles (${error.message}); usando fallback de sistema.`)
    rstkFontCssCache = { css: RSTK_FONT_CSS_FALLBACK, expiresAt: now + 60_000 }
    return RSTK_FONT_CSS_FALLBACK
  } finally {
    clearTimeout(timeout)
  }
}

export async function getSitesFontFile(urlValue) {
  const rawUrl = cleanString(urlValue)
  let parsed
  try {
    parsed = new URL(rawUrl)
  } catch {
    const error = new Error('URL de fuente inválida')
    error.status = 400
    throw error
  }

  if (parsed.protocol !== 'https:' || parsed.hostname !== 'fonts.gstatic.com') {
    const error = new Error('Fuente no permitida')
    error.status = 400
    throw error
  }

  const cacheKey = parsed.toString()
  const cached = rstkFontFileCache.get(cacheKey)
  if (cached) return cached

  const response = await fetch(cacheKey, {
    headers: {
      'user-agent': 'Mozilla/5.0 Ristak Sites Font Loader'
    }
  })
  if (!response.ok) {
    const error = new Error('No se pudo cargar el archivo de fuente')
    error.status = 502
    throw error
  }

  const result = {
    buffer: Buffer.from(await response.arrayBuffer()),
    contentType: response.headers.get('content-type') || 'font/woff2'
  }
  if (rstkFontFileCache.size >= RSTK_FONT_FILE_CACHE_MAX_ITEMS) {
    const oldestKey = rstkFontFileCache.keys().next().value
    if (oldestKey) rstkFontFileCache.delete(oldestKey)
  }
  rstkFontFileCache.set(cacheKey, result)
  return result
}

// Espejo del frontend getFieldOwnStyleClass: estilo elegido SOLO para este campo
// (override del estilo global). Vacío = hereda el global. Devuelve el sufijo de
// clases para <section class="rstk-field">: rstk-fieldstyled (resetea residuos del
// global) + la variante. Debe ir en lockstep con sitesCanvas.css / Sites.tsx.
function getFieldOwnStyleClass(block) {
  const settings = (block && block.settings) || {}
  let variant = ''
  if (block.blockType === 'radio' || block.blockType === 'checkboxes') {
    const raw = cleanString(settings.choiceStyle)
    if (raw) variant = `rstk-choice-${normalizeFormChoiceStyle(raw)}`
  } else if (block.blockType === 'dropdown') {
    const raw = cleanString(settings.selectStyle)
    if (raw) variant = `rstk-select-${normalizeFormSelectStyle(raw)}`
  } else {
    const raw = cleanString(settings.inputStyle)
    if (raw) variant = `rstk-input-${normalizeFormInputStyle(raw)}`
  }
  return variant ? ` rstk-fieldstyled ${variant}` : ''
}

// Pixel base de Meta (bootstrap + init + PageView). Va en el <head> para que el
// Meta Pixel Helper lo detecte aunque la página no tenga eventos de conversión.
function buildMetaPixelBaseScript(pixelId) {
  return `
  <script>
    !function(f,b,e,v,n,t,s){if(f.fbq)return;n=f.fbq=function(){n.callMethod?
    n.callMethod.apply(n,arguments):n.queue.push(arguments)};if(!f._fbq)f._fbq=n;
    n.push=n;n.loaded=!0;n.version='2.0';n.queue=[];t=b.createElement(e);t.async=!0;
    t.src=v;s=b.getElementsByTagName(e)[0];s.parentNode.insertBefore(t,s)}
    (window, document,'script','https://connect.facebook.net/en_US/fbevents.js');
    fbq('init', ${JSON.stringify(pixelId)});
    fbq('track', 'PageView');
    (function(){
      var KEY = 'rstk_meta_deferred';
      var STD = ['Lead','Schedule','Purchase','ViewContent','CompleteRegistration','Contact'];
      // Guarda un evento de conversión para re-emitirlo en la página siguiente,
      // por si un redirect canceló su beacon en la página donde ocurrió la acción.
      window.ristakMetaStashDeferredEvent = function(name, id, data){
        try { sessionStorage.setItem(KEY, JSON.stringify({ name: name, id: id, data: data || {}, ts: Date.now() })); } catch (e) {}
      };
      // Al cargar la página: si venimos de una conversión reciente, la re-emitimos
      // con el MISMO event_id (Meta deduplica -> cuenta una sola vez). One-shot + 90s.
      try {
        var raw = sessionStorage.getItem(KEY);
        if (raw) {
          sessionStorage.removeItem(KEY);
          var ev = JSON.parse(raw);
          if (ev && ev.id && ev.name && (Date.now() - (ev.ts || 0)) < 90000 && window.fbq) {
            var m = STD.indexOf(ev.name) >= 0 ? 'track' : 'trackCustom';
            window.fbq(m, ev.name, ev.data || {}, { eventID: ev.id });
          }
        }
      } catch (e) {}
    })();
  </script>
  <noscript><img height="1" width="1" style="display:none" src="https://www.facebook.com/tr?id=${encodeURIComponent(pixelId)}&ev=PageView&noscript=1"/></noscript>`
}

async function buildMetaPixelSnippet(site, trackingEnabled, activePage = null, preview = false) {
  const empty = { head: '', body: '' }
  // Con un código de Test Events activo forzamos el pixel aunque la página esté en
  // anti-tracking, para poder verificar en vivo (el modo test expira solo a los 30 min).
  // Nunca en el preview del editor: ahí no debe dispararse ningún evento real.
  const testMode = !preview && await isMetaTestModeActive()
  if ((!trackingEnabled && !testMode) || !site.metaCapiEnabled) return empty

  const metaConfig = await getMetaConfig().catch(error => {
    logger.warn(`No se pudo leer Pixel ID de Meta para snippet de Site: ${error.message}`)
    return null
  })
  const pixelId = cleanString(metaConfig?.pixel_id || process.env.META_PIXEL_ID || process.env.META_DATASET_ID)
  if (!pixelId) return empty

  const submitEventName = getFormSubmitMetaEventName(site, activePage?.id)
  const submitCondition = getFormSubmitMetaCondition(site)
  const pageMeta = getPageMetaConfig(site, activePage?.id)
  const pageViewEventName = pageMeta?.trigger === 'page_view' ? pageMeta.eventName : ''
  const trackPageViewInBrowser = Boolean(pageViewEventName && pageViewEventName !== SITE_META_PAGE_VIEW_EVENT_NAME)
  const submitConfiguredCustomData = buildSiteMetaConfiguredCustomData(
    getFormSubmitMetaEventParameters(site, activePage?.id, submitEventName),
    submitEventName
  )
  const pageConfiguredCustomData = buildSiteMetaConfiguredCustomData(pageMeta?.parameters, pageViewEventName)

  // Helpers de eventos + disparo de page_view: van en el <body>, después del
  // tracking nativo, para que la identidad del visitante ya esté disponible.
  const body = `
  <script>
    const ristakMetaReadCookie = function(name) {
      try {
        const prefix = String(name || '') + '=';
        const cookie = String(document.cookie || '').split(';').map(item => item.trim()).find(item => item.indexOf(prefix) === 0);
        return cookie ? decodeURIComponent(cookie.slice(prefix.length)) : '';
      } catch (error) {
        return '';
      }
    };
    const ristakMetaCurrentParams = function() {
      let current = {};
      try { current = Object.fromEntries(new URL(window.location.href).searchParams.entries()); } catch (error) {}
      const stored = window.ristakPreservedParams ? window.ristakPreservedParams() : {};
      return Object.assign({}, stored || {}, current || {});
    };
    const ristakMetaIdentity = function() {
      try {
        return window.ristakNativeIdentity ? window.ristakNativeIdentity() : {};
      } catch (error) {
        return {};
      }
    };
    const ristakMetaTracking = function(extra) {
      try {
        return window.ristakNativeBuildData ? window.ristakNativeBuildData(extra || {}) : null;
      } catch (error) {
        return null;
      }
    };
    window.ristakMetaBuildMetaPayload = function(extra) {
      const identity = ristakMetaIdentity();
      const base = {
        pageUrl: window.location.href,
        referrer: document.referrer,
        params: ristakMetaCurrentParams(),
        eventTime: Date.now(),
        visitorId: identity.visitorId || null,
        sessionId: identity.sessionId || null,
        contactId: identity.contactId || null,
        tracking: ristakMetaTracking({ conversion_type: 'meta_capi_event' }),
        fbp: ristakMetaReadCookie('_fbp') || null,
        fbc: ristakMetaReadCookie('_fbc') || null
      };
      const payload = Object.assign({}, base, extra || {});
      if (!payload.params || typeof payload.params !== 'object') payload.params = base.params;
      if (!payload.eventTime) payload.eventTime = base.eventTime;
      if (!payload.visitorId) payload.visitorId = base.visitorId;
      if (!payload.sessionId) payload.sessionId = base.sessionId;
      if (!payload.contactId) payload.contactId = base.contactId;
      if (!payload.tracking) payload.tracking = base.tracking;
      if (!payload.fbp) payload.fbp = base.fbp;
      if (!payload.fbc) payload.fbc = base.fbc;
      return payload;
    };
    const RISTAK_META_SUBMIT_CONDITION = ${JSON.stringify(submitCondition)};
    const ristakMetaSubmitIsDisqualified = function(customData) {
      const data = customData && typeof customData === 'object' ? customData : {};
      const status = String(data.status || data.formStatus || data.form_status || '').toLowerCase();
      const flags = [data.disqualified, data.formDisqualified, data.form_disqualified];
      return status === 'disqualified' || flags.some(function(value) {
        return value === true || String(value || '').toLowerCase() === 'true' || String(value || '') === '1';
      });
    };
    window.ristakMetaTrackSiteEvent = function(eventName, eventId, customData) {
      if (!window.fbq) return;
      const normalizedEventName = eventName || ${JSON.stringify(submitEventName)};
      if (!normalizedEventName || normalizedEventName === ${JSON.stringify(SITE_META_NO_EVENT)}) return;
      const method = ${JSON.stringify([...META_STANDARD_PIXEL_EVENTS])}.indexOf(normalizedEventName) >= 0 ? 'track' : 'trackCustom';
      const data = Object.assign({
        source: 'ristak_site',
        site_id: ${JSON.stringify(site.id)},
        site_name: ${JSON.stringify(site.name || '')},
        content_name: ${JSON.stringify(site.title || site.name || '')}
      }, customData || {});
      const options = eventId ? { eventID: eventId } : undefined;
      if (options) {
        window.fbq(method, normalizedEventName, data, options);
      } else {
        window.fbq(method, normalizedEventName, data);
      }
      // Diferido: guarda el evento para RE-disparalo al cargar la página siguiente
      // (si un redirect canceló este beacon). Mismo event_id => Meta deduplica y
      // cuenta una sola vez. Solo con event_id (la llave de dedup).
      if (eventId && window.ristakMetaStashDeferredEvent) {
        window.ristakMetaStashDeferredEvent(normalizedEventName, eventId, data);
      }
    };
    window.ristakMetaTrackSiteSubmit = function(eventId, customData, eventName) {
      const submitCustomData = Object.assign({}, ${scriptJson(submitConfiguredCustomData)}, customData || {});
      const submitCondition = String(submitCustomData.submit_condition || submitCustomData.submitCondition || RISTAK_META_SUBMIT_CONDITION || 'always');
      if (submitCondition === 'qualified_only' && ristakMetaSubmitIsDisqualified(submitCustomData)) return;
      window.ristakMetaTrackSiteEvent(
        eventName || ${JSON.stringify(submitEventName)},
        eventId,
        submitCustomData
      );
    };
    window.ristakMetaSendServerEvent = function(payload) {
      const requestPayload = Object.assign({}, payload || {});
      requestPayload.meta = window.ristakMetaBuildMetaPayload(requestPayload.meta || {});
      fetch('/api/sites/public/meta-event', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(requestPayload),
        keepalive: true
      }).catch(() => {});
    };
    ${pageViewEventName ? `
    try {
      const pageEventId = [
        'site_page',
        ${JSON.stringify(site.id)},
        ${JSON.stringify(activePage?.id || '')},
        Date.now(),
        Math.random().toString(16).slice(2)
      ].join('_');
      const pageData = {
        conversion_type: 'page_view',
        public_page_id: ${JSON.stringify(activePage?.id || '')},
        public_page_title: ${JSON.stringify(activePage?.title || '')}
      };
      Object.assign(pageData, ${scriptJson(pageConfiguredCustomData)});
      ${trackPageViewInBrowser ? `
      window.ristakMetaTrackSiteEvent(${JSON.stringify(pageViewEventName)}, pageEventId, pageData);
      ` : ''}
      window.ristakMetaSendServerEvent({
        siteId: ${JSON.stringify(site.id)},
        pageId: ${JSON.stringify(activePage?.id || '')},
        eventId: pageEventId,
        eventName: ${JSON.stringify(pageViewEventName)},
        trigger: 'page_view',
        meta: window.ristakMetaBuildMetaPayload({ conversionType: 'page_view' })
      });
    } catch (error) {}
    ` : ''}
  </script>`

  return { head: buildMetaPixelBaseScript(pixelId), body }
}

function getCalendarSiteMetaEventConfig(calendar = {}, siteOverride = null) {
  const source = calendar.customEvents && typeof calendar.customEvents === 'object'
    ? calendar.customEvents
    : calendar.custom_events && typeof calendar.custom_events === 'object'
      ? calendar.custom_events
      : {}
  const eventName = normalizeSiteMetaEventName(source.eventName || source.event_name, {
    allowNone: true,
    fallback: 'Schedule'
  })
  const rawChannel = cleanString(source.channel || source.conversionChannel || source.conversion_channel || 'site').toLowerCase()
  const channel = rawChannel === 'whatsapp'
    ? 'whatsapp'
    : rawChannel === 'smart'
      ? 'smart'
      : 'site'

  // El SITIO es master: si trae un override de evento valido, FUERZA canal 'site' y
  // enabled=true (aunque el calendario tenga Meta apagado o en whatsapp), y usa ese
  // evento. Los parametros se heredan del calendario (pruned al evento override).
  const overrideEventName = siteOverride && siteOverride.eventName
    ? normalizeSiteMetaEventName(siteOverride.eventName, { allowNone: true, fallback: SITE_META_NO_EVENT })
    : SITE_META_NO_EVENT
  if (overrideEventName && overrideEventName !== SITE_META_NO_EVENT) {
    return {
      enabled: true,
      channel: 'site',
      eventName: overrideEventName,
      parameters: pruneSiteMetaEventParametersForEvent(
        siteOverride?.parameters || siteOverride?.eventParameters || source.parameters || source.eventParameters || source.event_parameters || {},
        overrideEventName
      )
    }
  }

  return {
    enabled: normalizeBoolean(source.enabled) === 1,
    channel,
    eventName: eventName === SITE_META_NO_EVENT ? SITE_META_NO_EVENT : eventName,
    parameters: pruneSiteMetaEventParametersForEvent(source.parameters || source.eventParameters || source.event_parameters || {}, eventName)
  }
}

function buildCalendarMetaBaseCustomData(calendar = {}, appointment = {}, extra = {}) {
  return {
    source: 'ristak_calendar',
    conversion_type: 'appointment_booked',
    calendar_id: cleanString(calendar.id),
    calendar_name: cleanString(calendar.name),
    appointment_id: cleanString(appointment.id),
    appointment_status: cleanString(appointment.appointmentStatus || appointment.appointment_status || appointment.status || 'booked'),
    appointment_start_time: cleanString(appointment.startTime || appointment.start_time),
    appointment_end_time: cleanString(appointment.endTime || appointment.end_time),
    content_name: cleanString(calendar.eventTitle || calendar.event_title || calendar.name || 'Cita'),
    status: 'booked',
    ...extra
  }
}

function buildImportedHtmlConversionBaseCustomData(conversion = {}, site = {}, options = {}) {
  const conversionType = cleanString(conversion.conversionType) || 'form_submit'
  const status = cleanString(conversion.status) || cleanString(options.status)
  const accountCurrency = cleanString(options.currency)

  return {
    source: 'ristak_imported_html',
    conversion_type: conversionType,
    site_id: site.id,
    site_name: site.name,
    imported_html: true,
    ...(conversion.label ? { imported_conversion_label: conversion.label } : {}),
    ...(conversion.source ? { imported_conversion_source: conversion.source } : {}),
    ...(accountCurrency ? { currency: accountCurrency } : {}),
    ...(status ? { status } : {}),
    ...(conversion.submitCondition ? { submit_condition: conversion.submitCondition } : {}),
    ...(conversion.contentName ? { content_name: conversion.contentName } : { content_name: site.title || site.name }),
    ...(conversion.contentCategory ? { content_category: conversion.contentCategory } : {}),
    ...(conversion.orderId ? { order_id: conversion.orderId } : {}),
    ...(conversion.calendarId ? { calendar_id: conversion.calendarId } : {}),
    ...(conversion.calendarName ? { calendar_name: conversion.calendarName } : {}),
    ...(conversion.appointmentId ? { appointment_id: conversion.appointmentId } : {}),
    ...(conversion.appointmentStatus ? { appointment_status: conversion.appointmentStatus } : {}),
    ...(conversion.appointmentStartTime ? { appointment_start_time: conversion.appointmentStartTime } : {}),
    ...(conversion.appointmentEndTime ? { appointment_end_time: conversion.appointmentEndTime } : {}),
    ...(conversion.paymentId ? { payment_id: conversion.paymentId } : {}),
    ...(conversion.paymentStatus ? { payment_status: conversion.paymentStatus } : {})
  }
}

export async function buildCalendarMetaPixelSnippet(calendar = {}, { trackingEnabled = true, preview = false, siteOverride = null } = {}) {
  const config = getCalendarSiteMetaEventConfig(calendar, siteOverride)
  // El pixel base (init + PageView) solo necesita que el Meta del calendario esté
  // activado, aunque no haya un evento de conversión configurado (solo PageView).
  // Con código de Test Events activo se fuerza aunque esté en anti-tracking (no en preview).
  const testMode = await isMetaTestModeActive()
  if ((!trackingEnabled && !testMode) || preview || !config.enabled) return ''

  const metaConfig = await getMetaConfig().catch(error => {
    logger.warn(`No se pudo leer Pixel ID de Meta para snippet de calendario: ${error.message}`)
    return null
  })
  const pixelId = cleanString(metaConfig?.pixel_id || process.env.META_PIXEL_ID || process.env.META_DATASET_ID)
  if (!pixelId) return ''

  const baseScript = buildMetaPixelBaseScript(pixelId)
  // El helper de conversión (Schedule, etc.) solo aplica a canales de Meta con un
  // evento real; si no, el calendario carga únicamente el PageView.
  const wantsConversionEvent = ['site', 'smart'].includes(config.channel) && config.eventName !== SITE_META_NO_EVENT
  if (!wantsConversionEvent) return baseScript

  const configuredCustomData = buildSiteMetaConfiguredCustomData(config.parameters, config.eventName)
  const baseCustomData = buildCalendarMetaBaseCustomData(calendar, {}, {
    appointment_id: '',
    appointment_status: '',
    appointment_start_time: '',
    appointment_end_time: ''
  })

  return `${baseScript}
  <script>
    window.ristakMetaTrackCalendarEvent = function(eventName, eventId, customData) {
      if (!window.fbq) return;
      const normalizedEventName = eventName || ${JSON.stringify(config.eventName)};
      if (!normalizedEventName || normalizedEventName === ${JSON.stringify(SITE_META_NO_EVENT)}) return;
      const method = ${JSON.stringify([...META_STANDARD_PIXEL_EVENTS])}.indexOf(normalizedEventName) >= 0 ? 'track' : 'trackCustom';
      const data = Object.assign({}, ${scriptJson(baseCustomData)}, ${scriptJson(configuredCustomData)}, customData || {});
      const options = eventId ? { eventID: eventId } : undefined;
      if (options) {
        window.fbq(method, normalizedEventName, data, options);
      } else {
        window.fbq(method, normalizedEventName, data);
      }
      // Diferido: re-emite en la página siguiente con el mismo event_id (dedup).
      if (eventId && window.ristakMetaStashDeferredEvent) {
        window.ristakMetaStashDeferredEvent(normalizedEventName, eventId, data);
      }
    };
  </script>`
}

function isImportedHtmlSite(site = {}) {
  return site?.theme?.importedHtml === true || cleanString(site?.theme?.template) === IMPORTED_SITE_TEMPLATE
}

function buildImportedFormCaptureScript(site, imported, { pageId = DEFAULT_FUNNEL_PAGE_ID } = {}) {
  // Los tombstones viven en DB para recuperar asociaciones cuando el código
  // reaparece, pero jamás se publican al navegador ni participan en submits.
  const mappings = Array.isArray(imported?.formMappings)
    ? imported.formMappings
      .filter(mapping => (
        mapping?.present !== false && !isImportedRuntimeAmbiguousFormMapping(mapping)
      ))
      .map(mapping => ({
        ...mapping,
        fields: Array.isArray(mapping?.fields)
          ? mapping.fields.filter(field => field?.present !== false)
          : []
      }))
    : []

  return `
  <script>
    (() => {
      const SITE_ID = ${scriptJson(site.id)};
      const FORMS = ${scriptJson(mappings)};
      const DEFAULT_FORM_ID = ${scriptJson(mappings[0]?.formId || 'form_1')};
      const TRACKING = window.ristakNativeTracking || {};

      const cssEscape = (value) => String(value || '').replace(/["\\\\]/g, '\\\\$&');
      const readCookie = (name) => {
        const escaped = String(name || '').replace(/[^a-zA-Z0-9_-]/g, '');
        return (document.cookie.match(new RegExp('(?:^|; )' + escaped + '=([^;]+)')) || [])[1] || null;
      };
      const getParams = () => {
        // Params preservados de la sesión + los de la URL actual (estos ganan),
        // para no perder atribución si una navegación intermedia los quitó.
        const stored = window.ristakPreservedParams ? window.ristakPreservedParams() : {};
        let current = {};
        try {
          current = Object.fromEntries(new URL(window.location.href).searchParams.entries());
        } catch (_) {}
        return Object.assign({}, stored, current);
      };
      const getStableFieldId = (field) => (
        field.getAttribute('data-rstk-field-id') ||
        field.getAttribute('data-ristak-field-id') ||
        field.getAttribute('data-ristack-field-id') ||
        ''
      );
      const getFieldKey = (field, fallback) => (
        getStableFieldId(field) ||
        field.getAttribute('name') ||
        field.getAttribute('id') ||
        field.getAttribute('data-rstk-field') ||
        field.getAttribute('data-ristak-field') ||
        field.getAttribute('data-ristack-field') ||
        fallback
      );
      const getChoiceFields = (field, form, type) => {
        const stableFieldId = getStableFieldId(field);
        if (stableFieldId) {
          return Array.from(form.querySelectorAll('input')).filter(item => (
            String(item.type || '').toLowerCase() === type &&
            getStableFieldId(item) === stableFieldId
          ));
        }
        const name = field.getAttribute('name');
        if (!name) return [field];
        return Array.from(form.querySelectorAll('[name="' + cssEscape(name) + '"]'))
          .filter(item => String(item.type || '').toLowerCase() === type);
      };
      const readFieldValue = (field, form) => {
        const type = String(field.type || '').toLowerCase();
        if (type === 'checkbox') {
          return getChoiceFields(field, form, type)
            .filter(item => item.checked)
            .map(item => item.value || 'true');
        }
        if (type === 'radio') {
          const checked = getChoiceFields(field, form, type).find(item => item.checked) || null;
          return checked ? checked.value : '';
        }
        if (field.tagName === 'SELECT' && field.multiple) {
          return Array.from(field.selectedOptions || []).map(option => option.value || option.textContent || '').filter(Boolean);
        }
        return field.value || '';
      };
      const collectRawFields = (form) => {
        const raw = {};
        const fields = Array.from(form.querySelectorAll('input, select, textarea'));
        fields.forEach((field, index) => {
          const type = String(field.type || '').toLowerCase();
          if (['submit', 'button', 'reset', 'image', 'hidden'].includes(type)) return;
          const key = getFieldKey(field, 'field_' + (index + 1));
          if (!key) return;
          const value = readFieldValue(field, form);
          if (Array.isArray(value) ? value.length > 0 : String(value || '').trim()) {
            raw[key] = value;
          }
        });
        return raw;
      };
      const parseChoiceActions = (field) => {
        const raw = field.getAttribute('data-rstk-choice-actions') || field.getAttribute('data-ristak-choice-actions') || field.getAttribute('data-ristack-choice-actions') || '';
        if (!raw) return [];
        try {
          const parsed = JSON.parse(raw);
          return Array.isArray(parsed) ? parsed.filter(item => item && item.action && item.action !== 'none') : [];
        } catch (_) {
          return [];
        }
      };
      const collectSelectedChoiceActions = (form) => {
        const actions = [];
        Array.from(form.querySelectorAll('input[type="radio"]:checked, input[type="checkbox"]:checked')).forEach((field) => {
          parseChoiceActions(field).forEach(action => {
            actions.push({
              ...action,
              choiceName: field.getAttribute('name') || field.getAttribute('id') || '',
              choiceValue: field.value || ''
            });
          });
        });
        Array.from(form.querySelectorAll('select')).forEach((select) => {
          Array.from(select.selectedOptions || []).forEach((option) => {
            parseChoiceActions(option).forEach(action => {
              actions.push({
                ...action,
                choiceName: select.getAttribute('name') || select.getAttribute('id') || '',
                choiceValue: option.value || option.textContent || ''
              });
            });
          });
        });
        return actions;
      };
      const parseObjectAttr = (element, names) => {
        if (!element || !element.getAttribute) return {};
        for (const name of names) {
          const raw = element.getAttribute(name);
          if (!raw) continue;
          try {
            const parsed = JSON.parse(raw);
            return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
          } catch (_) {
            return {};
          }
        }
        return {};
      };
      const firstAttr = (element, names) => {
        if (!element || !element.getAttribute) return '';
        for (const name of names) {
          const value = element.getAttribute(name);
          if (value !== null && value !== undefined && String(value).trim()) return String(value).trim();
        }
        return '';
      };
      const setIfValue = (target, key, value) => {
        if (value !== null && value !== undefined && String(value).trim()) target[key] = String(value).trim();
      };
      const readConversionConfig = (element) => {
        const data = Object.assign({},
          parseObjectAttr(element, ['data-rstk-conversion-data', 'data-ristak-conversion-data', 'data-ristack-conversion-data']),
          parseObjectAttr(element, ['data-rstk-meta-data', 'data-ristak-meta-data', 'data-ristack-meta-data'])
        );
        setIfValue(data, 'eventName', firstAttr(element, ['data-rstk-conversion-event', 'data-ristak-conversion-event', 'data-ristack-conversion-event', 'data-rstk-meta-event-name', 'data-meta-event-name']));
        setIfValue(data, 'conversionType', firstAttr(element, ['data-rstk-conversion-type', 'data-ristak-conversion-type', 'data-ristack-conversion-type']));
        setIfValue(data, 'submitCondition', firstAttr(element, ['data-rstk-conversion-condition', 'data-ristak-conversion-condition', 'data-ristack-conversion-condition', 'data-rstk-submit-condition', 'data-ristak-submit-condition', 'data-ristack-submit-condition']));
        setIfValue(data, 'value', firstAttr(element, ['data-rstk-conversion-value', 'data-ristak-conversion-value', 'data-ristack-conversion-value']));
        setIfValue(data, 'currency', firstAttr(element, ['data-rstk-conversion-currency', 'data-ristak-conversion-currency', 'data-ristack-conversion-currency']));
        setIfValue(data, 'contentName', firstAttr(element, ['data-rstk-conversion-content-name', 'data-ristak-conversion-content-name', 'data-ristack-conversion-content-name']));
        setIfValue(data, 'contentCategory', firstAttr(element, ['data-rstk-conversion-content-category', 'data-ristak-conversion-content-category', 'data-ristack-conversion-content-category']));
        setIfValue(data, 'contentIds', firstAttr(element, ['data-rstk-conversion-content-ids', 'data-ristak-conversion-content-ids', 'data-ristack-conversion-content-ids']));
        setIfValue(data, 'contentType', firstAttr(element, ['data-rstk-conversion-content-type', 'data-ristak-conversion-content-type', 'data-ristack-conversion-content-type']));
        setIfValue(data, 'numItems', firstAttr(element, ['data-rstk-conversion-num-items', 'data-ristak-conversion-num-items', 'data-ristack-conversion-num-items']));
        setIfValue(data, 'orderId', firstAttr(element, ['data-rstk-conversion-order-id', 'data-ristak-conversion-order-id', 'data-ristack-conversion-order-id']));
        setIfValue(data, 'status', firstAttr(element, ['data-rstk-conversion-status', 'data-ristak-conversion-status', 'data-ristack-conversion-status']));
        setIfValue(data, 'calendarId', firstAttr(element, ['data-rstk-calendar-id', 'data-ristak-calendar-id', 'data-ristack-calendar-id']));
        setIfValue(data, 'calendarName', firstAttr(element, ['data-rstk-calendar-name', 'data-ristak-calendar-name', 'data-ristack-calendar-name']));
        setIfValue(data, 'appointmentId', firstAttr(element, ['data-rstk-appointment-id', 'data-ristak-appointment-id', 'data-ristack-appointment-id']));
        setIfValue(data, 'appointmentStatus', firstAttr(element, ['data-rstk-appointment-status', 'data-ristak-appointment-status', 'data-ristack-appointment-status']));
        setIfValue(data, 'appointmentStartTime', firstAttr(element, ['data-rstk-appointment-start-time', 'data-ristak-appointment-start-time', 'data-ristack-appointment-start-time']));
        setIfValue(data, 'appointmentEndTime', firstAttr(element, ['data-rstk-appointment-end-time', 'data-ristak-appointment-end-time', 'data-ristack-appointment-end-time']));
        setIfValue(data, 'paymentId', firstAttr(element, ['data-rstk-payment-id', 'data-ristak-payment-id', 'data-ristack-payment-id']));
        setIfValue(data, 'paymentStatus', firstAttr(element, ['data-rstk-payment-status', 'data-ristak-payment-status', 'data-ristack-payment-status']));
        return data;
      };
      const collectConversionParamFields = (form) => {
        const params = {};
        Array.from(form.querySelectorAll('[data-rstk-conversion-param], [data-ristak-conversion-param], [data-ristack-conversion-param], [data-rstk-meta-param], [data-ristak-meta-param], [data-ristack-meta-param]')).forEach((field) => {
          const key = firstAttr(field, ['data-rstk-conversion-param', 'data-ristak-conversion-param', 'data-ristack-conversion-param', 'data-rstk-meta-param', 'data-ristak-meta-param', 'data-ristack-meta-param']);
          if (!key) return;
          const value = readFieldValue(field, form);
          if (Array.isArray(value) ? value.length > 0 : String(value || '').trim()) params[key] = value;
        });
        return params;
      };
      const collectImportedConversion = (form, submitter) => {
        const data = Object.assign({},
          readConversionConfig(form),
          readConversionConfig(submitter),
          collectConversionParamFields(form)
        );
        const keys = Object.keys(data).filter(key => {
          const value = data[key];
          return Array.isArray(value) ? value.length > 0 : String(value || '').trim();
        });
        return keys.length ? data : null;
      };
      const resolveFormId = (form, index) => (
        form.getAttribute('data-rstk-form-id') ||
        form.getAttribute('data-ristak-form-id') ||
        form.getAttribute('data-ristack-form-id') ||
        form.getAttribute('data-rstk-form') ||
        form.getAttribute('data-ristak-form') ||
        form.getAttribute('data-ristack-form') ||
        form.getAttribute('id') ||
        form.getAttribute('name') ||
        (FORMS[index] && FORMS[index].formId) ||
        DEFAULT_FORM_ID
      );
      const setMessage = (form, text, state) => {
        let message = form.querySelector('[data-rstk-import-message]');
        if (!message) {
          message = document.createElement('div');
          message.setAttribute('data-rstk-import-message', 'true');
          message.style.marginTop = '12px';
          message.style.font = '500 14px/1.45 "Inter", Arial, sans-serif';
          form.appendChild(message);
        }
        message.textContent = text;
        message.style.color = state === 'error' ? '#b91c1c' : '#166534';
      };
      const showImportedMessageOnly = (form, text) => {
        Array.from(form.querySelectorAll('input, select, textarea, button')).forEach((element) => {
          const type = String(element.type || '').toLowerCase();
          if (type === 'hidden') return;
          const wrapper = element.closest('label, .field, .form-field, .form-group, .rstk-field') || element;
          wrapper.hidden = true;
        });
        setMessage(form, text || 'Gracias. Por ahora no califica.', 'success');
      };

      const calendarBookingFormAttrs = [
        'data-rstk-calendar-book-form',
        'data-ristak-calendar-book-form',
        'data-ristack-calendar-book-form'
      ];
      const nativeCalendarAttrs = [
        'data-rstk-native-element', 'data-ristak-native-element', 'data-ristack-native-element',
        'data-rstk-element', 'data-ristak-element', 'data-ristack-element',
        'data-rstk-element-type', 'data-ristak-element-type', 'data-ristack-element-type',
        'data-rstk-component', 'data-ristak-component', 'data-ristack-component',
        'data-rstk-widget', 'data-ristak-widget', 'data-ristack-widget',
        'data-rstk-native-type'
      ];
      const calendarTokens = new Set(['calendar', 'calendars', 'calendario', 'calendarios', 'agenda', 'cita', 'citas', 'booking', 'appointment', 'appointments']);
      const isCalendarBookingForm = (form) => {
        if (calendarBookingFormAttrs.some(name => form.hasAttribute && form.hasAttribute(name))) return true;
        let element = form.parentElement;
        while (element) {
          const value = nativeCalendarAttrs.map(name => element.getAttribute && element.getAttribute(name)).find(Boolean);
          const token = String(value || '').trim().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[_\s]+/g, '-');
          if (calendarTokens.has(token)) return true;
          element = element.parentElement;
        }
        return false;
      };
      const importedForms = Array.from(document.querySelectorAll('form')).filter(form => !isCalendarBookingForm(form));
      const initImportedContactPrefill = () => {
        const apply = () => {
          if (!window.ristakNativeInitContactPrefill) return;
          importedForms.forEach(form => window.ristakNativeInitContactPrefill(form));
        };
        apply();
        window.setTimeout(apply, 0);
        window.addEventListener('ristak:native-ready', apply, { once: true });
      };

      initImportedContactPrefill();

      importedForms.forEach((form, index) => {
        form.setAttribute('data-rstk-import-form', 'true');
        // Al elegir una opción que descalifica solo mostramos un aviso debajo del
        // campo; la descalificación real ocurre al enviar, no al elegir.
        const clearImportedNotice = () => {
          const notice = form.querySelector('[data-rstk-disqualify-notice]');
          if (notice) { notice.hidden = true; notice.textContent = ''; }
        };
        const showImportedNotice = (anchor, text) => {
          let notice = form.querySelector('[data-rstk-disqualify-notice]');
          if (!notice) {
            notice = document.createElement('div');
            notice.setAttribute('data-rstk-disqualify-notice', 'true');
            notice.style.cssText = 'margin:8px 0 0;padding:8px 11px;border-radius:8px;border:1px solid rgba(217,119,6,.4);background:rgba(217,119,6,.1);color:inherit;font:600 13px/1.4 inherit';
          }
          notice.textContent = text;
          notice.hidden = false;
          const ref = anchor && anchor.closest ? (anchor.closest('label, .field, .form-field, .form-group, .rstk-field') || anchor) : anchor;
          if (ref && ref.parentNode) ref.parentNode.insertBefore(notice, ref.nextSibling);
          else form.appendChild(notice);
        };
        form.addEventListener('change', (event) => {
          const target = event.target;
          if (!target || !target.matches) return;
          if (!target.matches('input[type="radio"], input[type="checkbox"], select')) return;
          const warnAction = collectSelectedChoiceActions(form).find(item => (
            (item.action === 'disqualify' || item.action === 'disqualify_after_submit') &&
            (item.warnBeforeDisqualify === true || item.warn_before_disqualify === true)
          )) || null;
          if (warnAction) showImportedNotice(target, warnAction.disqualifyNoticeMessage || warnAction.disqualify_notice_message || 'Con esta respuesta es posible que no califiques para continuar.');
          else clearImportedNotice();
        });
        form.addEventListener('submit', async (event) => {
          event.preventDefault();
          const submitter = event.submitter || form.querySelector('[type="submit"], button');
          if (submitter) submitter.disabled = true;
          setMessage(form, 'Enviando...', 'loading');
          try {
            const rawFields = collectRawFields(form);
            const selectedChoiceActions = collectSelectedChoiceActions(form);
            const importedConversion = collectImportedConversion(form, submitter);
            const disqualifyingAction = selectedChoiceActions.find(item => item.action === 'disqualify' || item.action === 'disqualify_after_submit') || null;
            // "Descalificar en esta página" corta el flujo al enviar (oculta el form);
            // "al terminar formulario" deja terminar y registra al contacto como no calificado.
            const immediateDisqualifyChoice = Boolean(disqualifyingAction && disqualifyingAction.action === 'disqualify');
            if (immediateDisqualifyChoice) form.dataset.rstkImmediateDisqualify = 'true';
            const response = await fetch('/api/sites/public/submit', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                siteId: SITE_ID,
                importedFormId: resolveFormId(form, index),
                rawFields,
                meta: {
                  pageId: ${scriptJson(pageId || DEFAULT_FUNNEL_PAGE_ID)},
                  pageUrl: window.location.href,
                  referrer: document.referrer,
                  params: getParams(),
                  eventTime: Date.now(),
                  visitorId: TRACKING.visitorId || null,
                  sessionId: TRACKING.sessionId || null,
                  tracking: TRACKING,
                  fbp: readCookie('_fbp'),
                  fbc: readCookie('_fbc'),
                  importedChoiceActions: selectedChoiceActions,
                  importedDisqualified: Boolean(disqualifyingAction),
                  importedDisqualifiedMessage: disqualifyingAction && disqualifyingAction.buttonMessage ? disqualifyingAction.buttonMessage : '',
                  immediateDisqualify: form.dataset.rstkImmediateDisqualify === 'true',
                  ...(importedConversion ? { importedConversion } : {})
                }
              })
            });
            const payload = await response.json().catch(() => ({}));
            if (!response.ok || payload.success === false) {
              throw new Error(payload.error || 'No se pudo enviar el formulario');
            }
            const submission = payload.data || {};
            const metaEventId = submission.capi && submission.capi.eventId
              ? submission.capi.eventId
              : (submission.submissionId ? 'site_' + SITE_ID + '_' + submission.submissionId : '');
            if (window.ristakMetaTrackSiteSubmit) {
              const capiCustomData = submission.capi && submission.capi.customData && typeof submission.capi.customData === 'object'
                ? submission.capi.customData
                : {};
              window.ristakMetaTrackSiteSubmit(metaEventId, Object.assign({
                status: submission.status || 'received',
                conversion_type: 'form_submit',
                imported_html: true,
                submit_condition: importedConversion && importedConversion.submitCondition ? importedConversion.submitCondition : ''
              }, capiCustomData), (submission.capi && submission.capi.eventName) || (importedConversion && importedConversion.eventName));
            }
            if (window.ristakNativeRememberContact && submission.contactId) {
              window.ristakNativeRememberContact(submission.contact || {
                contactId: submission.contactId,
                fullName: submission.contactName || '',
                email: submission.contactEmail || '',
                phone: submission.contactPhone || ''
              });
            }
            if (immediateDisqualifyChoice) {
              showImportedMessageOnly(form, (disqualifyingAction && disqualifyingAction.buttonMessage) || submission.message || 'Gracias. Por ahora no califica.');
              window.dispatchEvent(new CustomEvent('ristak:submitted', { detail: submission }));
              if (
                disqualifyingAction &&
                (disqualifyingAction.buttonPageId || disqualifyingAction.buttonUrl) &&
                typeof window.ristakRunImportedActions === 'function'
              ) {
                window.setTimeout(() => {
                  window.ristakRunImportedActions(form, [disqualifyingAction], {
                    source: 'choice_option',
                    submission
                  });
                }, 200);
              }
            } else {
              form.reset();
              clearImportedNotice();
              setMessage(form, submission.message || 'Listo. Recibimos tu información.', 'success');
              window.dispatchEvent(new CustomEvent('ristak:submitted', { detail: submission }));
              if (submission.status !== 'disqualified') {
                const navigationAction = selectedChoiceActions.find(item => (
                  (item.action === 'url' && item.buttonUrl) ||
                  (item.action === 'specific_page' && item.buttonPageId)
                ));
                if (navigationAction && typeof window.ristakRunImportedActions === 'function') {
                  window.setTimeout(() => {
                    window.ristakRunImportedActions(form, [navigationAction], { source: 'choice_option' });
                  }, 200);
                }
              }
              if (selectedChoiceActions.length && window.ristakRunImportedActions) {
                const followUpActions = selectedChoiceActions.filter(item => item.action !== 'submit');
                if (followUpActions.length) {
                  await window.ristakRunImportedActions(form, followUpActions, {
                    source: 'choice_option',
                    submission
                  });
                }
              }
            }
          } catch (error) {
            setMessage(form, error && error.message ? error.message : 'No se pudo enviar el formulario', 'error');
          } finally {
            delete form.dataset.rstkImmediateDisqualify;
            if (submitter) submitter.disabled = false;
          }
        });
      });
    })();
  </script>`
}

function buildImportedButtonActionScript(site, { pageId = DEFAULT_FUNNEL_PAGE_ID, linkStyle = 'query' } = {}) {
  const pages = normalizeSitePages(site)
  const pageList = pages.map(page => ({
    id: page.id,
    title: page.title || page.id
  }))
  const pageHrefs = Object.fromEntries(pages.map(page => [page.id, buildPublicPageRoutePath(site, page.id)]))

  return `
  <script>
    (() => {
      const PAGES = ${scriptJson(pageList)};
      const PAGE_HREFS = ${scriptJson(pageHrefs)};
      const LINK_STYLE = ${scriptJson(linkStyle)};
      const CURRENT_PAGE_ID = ${scriptJson(pageId || DEFAULT_FUNNEL_PAGE_ID)};
      // Conservar los params de la URL original (UTMs, fbclid, gclid, etc.)
      // en cualquier navegación o redirect disparado por acciones de botones.
      const preserveUrl = (value) => (
        value && window.ristakPreserveParams ? window.ristakPreserveParams(value) : value
      );
      const navigateTo = (value) => {
        const target = preserveUrl(value);
        if (!target) return false;
        if (window.parent && window.parent !== window) {
          window.parent.postMessage({ type: 'ristak:form-navigate', url: target }, '*');
          return true;
        }
        window.location.href = target;
        return true;
      };
      const getPageHref = (targetPageId) => {
        if (!targetPageId) return '#';
        if (LINK_STYLE === 'path' && PAGE_HREFS[targetPageId]) return preserveUrl(PAGE_HREFS[targetPageId]);
        const nextUrl = new URL(window.location.href);
        nextUrl.searchParams.set('page', targetPageId);
        return preserveUrl(nextUrl.toString());
      };
      const getNextPageId = () => {
        const index = PAGES.findIndex(page => page.id === CURRENT_PAGE_ID);
        const next = index >= 0 ? PAGES[index + 1] : PAGES[1];
        return next ? next.id : '';
      };
      const showActionMessage = (button, text, state = 'success') => {
        const host = button.closest('form') || button.parentElement || document.body;
        let message = host.querySelector('[data-rstk-button-action-message]');
        if (!message) {
          message = document.createElement('div');
          message.setAttribute('data-rstk-button-action-message', 'true');
          message.style.marginTop = '12px';
          message.style.font = '600 14px/1.45 "Inter", Arial, sans-serif';
          host.appendChild(message);
        }
        message.textContent = text;
        message.style.color = state === 'error' ? '#b91c1c' : '#166534';
      };
      const parseActions = (raw) => {
        if (!raw) return [];
        try {
          const parsed = JSON.parse(raw);
          return Array.isArray(parsed) ? parsed.filter(item => item && item.action && item.action !== 'none') : [];
        } catch (_) {
          return [];
        }
      };
      const isImportedPopupCandidate = (element) => {
        if (!element || !element.matches) return false;
        if (element.matches('[data-rstk-site-popup], dialog, [role="dialog"], [aria-modal="true"]')) return true;
        const signature = [
          element.id || '',
          typeof element.className === 'string' ? element.className : '',
          element.getAttribute('data-popup') || '',
          element.getAttribute('data-modal') || '',
          element.getAttribute('data-dialog') || ''
        ].join(' ').toLowerCase();
        return /(popup|pop-up|modal|dialog|lightbox|overlay|exit-intent|newsletter)/.test(signature);
      };
      const getImportedPopupCandidates = (source) => {
        const candidates = Array.from(document.querySelectorAll('dialog, [role="dialog"], [aria-modal="true"], [id], [class], [data-popup], [data-modal], [data-dialog]'))
          .filter(isImportedPopupCandidate);
        const closest = source && source.closest ? source.closest('dialog, [role="dialog"], [aria-modal="true"], [id], [class]') : null;
        return closest && isImportedPopupCandidate(closest)
          ? [closest, ...candidates.filter(item => item !== closest)]
          : candidates;
      };
      const openImportedPopup = (source) => {
        let opened = false;
        if (typeof window.ristakOpenSitePopup === 'function') {
          window.ristakOpenSitePopup();
          opened = true;
        }
        getImportedPopupCandidates(source).forEach(element => {
          try {
            if (element.tagName === 'DIALOG' && typeof element.showModal === 'function' && !element.open) {
              element.showModal();
            }
          } catch (_) {}
          element.hidden = false;
          element.removeAttribute('hidden');
          element.removeAttribute('aria-hidden');
          element.setAttribute('open', '');
          element.classList.add('open', 'active', 'show', 'is-open');
          const computed = window.getComputedStyle(element);
          if (computed.display === 'none') element.style.display = element.matches('[data-rstk-site-popup]') ? 'grid' : 'flex';
          opened = true;
        });
        return opened;
      };
      const closeImportedPopup = (source) => {
        let closed = false;
        if (typeof window.ristakCloseSitePopup === 'function') {
          window.ristakCloseSitePopup();
          closed = true;
        }
        getImportedPopupCandidates(source).forEach(element => {
          if (element.tagName === 'DIALOG' && typeof element.close === 'function' && element.open) {
            try { element.close(); } catch (_) {}
          }
          element.hidden = true;
          element.setAttribute('hidden', '');
          element.setAttribute('aria-hidden', 'true');
          element.removeAttribute('open');
          element.classList.remove('open', 'active', 'show', 'is-open');
          element.style.display = 'none';
          closed = true;
        });
        return closed;
      };
      const legacyActionFromElement = (element) => {
        const action = String(element.getAttribute('data-rstk-button-action') || element.getAttribute('data-ristak-button-action') || element.getAttribute('data-ristack-button-action') || '').trim();
        if (!action || action === 'none') return [];
        return [{
          action,
          buttonUrl: element.getAttribute('data-rstk-button-url') || element.getAttribute('data-ristak-button-url') || element.getAttribute('data-ristack-button-url') || element.getAttribute('href') || '',
          buttonPageId: element.getAttribute('data-rstk-button-page-id') || element.getAttribute('data-ristak-button-page-id') || element.getAttribute('data-ristack-button-page-id') || '',
          buttonMessage: element.getAttribute('data-rstk-button-message') || element.getAttribute('data-ristak-button-message') || element.getAttribute('data-ristack-button-message') || ''
        }];
      };
      const actionsFromElement = (element) => {
        const actions = parseActions(
          element.getAttribute('data-rstk-button-actions') ||
          element.getAttribute('data-ristak-button-actions') ||
          element.getAttribute('data-ristack-button-actions') ||
          ''
        );
        return actions.length ? actions : legacyActionFromElement(element);
      };
      const isSubmitter = (button) => (
        button &&
        button.matches &&
        button.matches('button:not([type]), button[type="submit"], input[type="submit"], input[type="image"]')
      );
      const submitFormAndWait = (form, button) => new Promise((resolve, reject) => {
        if (!form) {
          resolve(null);
          return;
        }
        let done = false;
        const timeout = window.setTimeout(() => {
          if (done) return;
          done = true;
          window.removeEventListener('ristak:submitted', handleSubmitted);
          reject(new Error('No se pudo confirmar el envío del formulario'));
        }, 10000);
        const handleSubmitted = (submitEvent) => {
          if (done) return;
          done = true;
          window.clearTimeout(timeout);
          window.removeEventListener('ristak:submitted', handleSubmitted);
          resolve(submitEvent.detail || null);
        };
        window.addEventListener('ristak:submitted', handleSubmitted);
        if (typeof form.requestSubmit === 'function') {
          form.requestSubmit(isSubmitter(button) ? button : undefined);
        } else {
          form.dispatchEvent(new Event('submit', { bubbles: true, cancelable: true }));
        }
      });
      const splitActions = (actions) => {
        const terminalNames = new Set(['url', 'next_page', 'specific_page']);
        const terminal = actions.find(item => terminalNames.has(item.action) || (item.action === 'disqualify' && (item.buttonPageId || item.buttonUrl)));
        const beforeTerminal = actions.filter(item => item !== terminal);
        return { beforeTerminal, terminal };
      };
      const runOneAction = async (source, action, context = {}) => {
        if (!action || !action.action || action.action === 'none') return;
        if (action.action === 'submit') {
          await submitFormAndWait(source.closest ? source.closest('form') : context.form, source);
          return;
        }
        if (action.action === 'open_popup') {
          if (!openImportedPopup(source)) showActionMessage(source, 'No encontramos un pop up para abrir', 'error');
          return;
        }
        if (action.action === 'close_popup') {
          if (!closeImportedPopup(source)) showActionMessage(source, 'No encontramos un pop up para cerrar', 'error');
          return;
        }
        if (action.action === 'automation' || action.action === 'notify_team' || action.action === 'add_tag' || action.action === 'send_whatsapp' || action.action === 'create_payment') {
          window.dispatchEvent(new CustomEvent('ristak:imported-action-demo', {
            detail: {
              action: action.action,
              label: action.automationName || '',
              pageId: CURRENT_PAGE_ID,
              context
            }
          }));
          showActionMessage(source, 'Acción demo registrada: ' + action.action, 'success');
          return;
        }
        if (action.action === 'disqualify') {
          const message = action.buttonMessage || 'Gracias. Por ahora esta solicitud no califica.';
          window.dispatchEvent(new CustomEvent('ristak:disqualified', { detail: { message, pageId: CURRENT_PAGE_ID, context } }));
          if (!action.buttonPageId) showActionMessage(source, message, 'error');
        }
      };
      const runTerminalAction = (source, action) => {
        if (!action) return;
        if (action.action === 'url') {
          const targetUrl = action.buttonUrl || (source.getAttribute ? source.getAttribute('href') : '') || '';
          if (targetUrl) window.location.href = preserveUrl(targetUrl);
          return;
        }
        if (action.action === 'next_page') {
          const nextPageId = getNextPageId();
          if (nextPageId) window.location.href = getPageHref(nextPageId);
          return;
        }
        if (action.action === 'disqualify' && action.buttonUrl) {
          window.location.href = preserveUrl(action.buttonUrl);
          return;
        }
        if (action.action === 'specific_page' || action.action === 'disqualify') {
          const targetPageId = action.buttonPageId || '';
          if (targetPageId) window.location.href = getPageHref(targetPageId);
        }
      };
      const runImportedActions = async (source, actions, context = {}) => {
        const cleanActions = Array.isArray(actions) ? actions.filter(item => item && item.action && item.action !== 'none') : [];
        if (!cleanActions.length) return;
        const { beforeTerminal, terminal } = splitActions(cleanActions);
        for (const action of beforeTerminal) {
          await runOneAction(source, action, context);
        }
        runTerminalAction(source, terminal);
      };
      window.ristakRunImportedActions = runImportedActions;

      document.addEventListener('click', (event) => {
        const button = event.target && event.target.closest
          ? event.target.closest('[data-rstk-button-action], [data-rstk-button-actions], [data-ristak-button-action], [data-ristak-button-actions], [data-ristack-button-action], [data-ristack-button-actions]')
          : null;
        if (!button) return;

        const actions = actionsFromElement(button);
        if (!actions.length) {
          event.preventDefault();
          return;
        }

        event.preventDefault();
        runImportedActions(button, actions, { source: 'button' }).catch(error => {
          showActionMessage(button, error && error.message ? error.message : 'No se pudo ejecutar la acción', 'error');
        });
      }, true);
    })();
  </script>`
}

async function buildImportedHtmlRuntimeInjection(site, imported, { trackingEnabled = true, pageId = DEFAULT_FUNNEL_PAGE_ID, pageTitle = '', preview = false, linkStyle = 'query' } = {}) {
  const activePageId = cleanString(pageId) || DEFAULT_FUNNEL_PAGE_ID
  const activePage = getSitePage(site, activePageId) || { id: activePageId, title: pageTitle || site.title || site.name }
  const metaPixel = await buildMetaPixelSnippet(site, trackingEnabled, {
    ...activePage,
    title: activePage.title || pageTitle || site.title || site.name
  }, preview)
  const nativeTrackingScript = trackingEnabled
    ? buildNativeSiteTrackingScript({
      siteId: site.id,
      siteSlug: site.slug,
      siteName: site.name,
      siteType: site.siteType,
      pageId: activePageId,
      pageTitle: pageTitle || site.title || site.name,
      formSiteId: site.id,
      formSiteName: site.name,
      endpoint: '/collect'
    })
    : ''
  const videoTrackingScript = trackingEnabled ? buildVideoPlaybackTrackingScript({ enabled: true }) : ''
  const buttonActionScript = buildImportedButtonActionScript(site, { pageId: activePageId, linkStyle })
  const captureScript = buildImportedFormCaptureScript(site, imported, { pageId: activePageId })
  const popupHtml = renderSitePopup(site)
  // El script de preservación de params va primero: define los helpers globales
  // que usan el tracking, los botones y la captura de formularios.
  const paramPreservationScript = buildParamPreservationScript()
  // head: pixel base de Meta (se inyecta en el <head> del HTML importado).
  // body: helpers/eventos y demás runtime (se inyecta antes de </body>).
  return {
    head: metaPixel.head,
    body: `${paramPreservationScript}${nativeTrackingScript}${metaPixel.body}${videoTrackingScript}${buttonActionScript}${captureScript}${popupHtml}`
  }
}

function injectImportedHtmlRuntime(html = '', injection = '') {
  html = html || '<!doctype html><html><body></body></html>'
  html = injectImportedStaticFallback(html)

  if (/<\/body>/i.test(html)) {
    return html.replace(/<\/body>/i, `${injection}</body>`)
  }

  return `${html}${injection}`
}

function getImportedRenderPage(site, pageId = '', pagePath = []) {
  const pages = normalizeSitePages(site)
  const requestedPageId = cleanString(pageId)
  const requestedPage = pages.find(page => page.id === requestedPageId)
  if (requestedPage) return requestedPage

  const pathPage = resolvePageByPathSegments(site, pagePath)
  return pathPage || pages[0] || null
}

function getImportedRenderPageByAssetPath(site, assetPath = '') {
  const normalizedAssetPath = normalizeImportedAssetPath(assetPath)
  if (!normalizedAssetPath) return null

  return normalizeSitePages(site).find(page => (
    normalizeImportedAssetPath(page.importedAssetPath || page.imported_asset_path) === normalizedAssetPath
  )) || null
}

function getImportedVideoUrlFromAttrs(attrsText = '') {
  const attrs = parseHtmlAttributes(attrsText)
  return cleanString(
    attrs['data-rstk-video-url'] ||
    attrs['data-ristak-video-url'] ||
    attrs['data-rstk-video-embed'] ||
    attrs.src ||
    attrs.data ||
    ''
  )
}

function hasImportedVideoSettings(attrsText = '') {
  const attrs = parseHtmlAttributes(attrsText)
  return Boolean(attrs['data-rstk-video-settings'] || attrs['data-ristak-video-settings'] || attrs['data-ristack-video-settings'])
}

function renderImportedVideoElementForRender({
  sourceHtml = '',
  tagName = '',
  openingTag = '',
  attrsText = '',
  selfClosing = false,
  site,
  context = {},
  index = 0
} = {}) {
  const attrs = parseHtmlAttributes(attrsText)
  const rawUrl = getImportedVideoUrlFromAttrs(attrsText)
  if (!rawUrl || !hasImportedVideoSettings(attrsText)) return sourceHtml

  let videoSource = rawUrl
  try {
    videoSource = normalizeImportedVideoEmbed(rawUrl).src || rawUrl
  } catch {
    videoSource = rawUrl
  }

  const editId = getImportedEditableAttr(attrs, 'id') || attrs.id || `imported-video-${index + 1}`
  const label = getImportedElementLabel(cleanString(tagName) || 'video', attrs, 'Video')
  const settings = getImportedVideoSettingsFromAttrs(attrsText, videoSource)
  const block = {
    id: editId,
    siteId: site?.id || '',
    blockType: 'video',
    label,
    content: videoSource,
    placeholder: '',
    required: false,
    options: [],
    settings,
    sortOrder: index,
    createdAt: '',
    updatedAt: ''
  }
  const renderedVideo = renderContentBlock(block, context)
  if (!renderedVideo) return sourceHtml

  const tag = cleanString(tagName).toLowerCase()
  const mediaTag = selfClosing || ['iframe', 'video', 'object', 'embed', 'wistia-player'].includes(tag)
  if (mediaTag) {
    return `<div class="rstk-imported-video-slot" data-rstk-editable="true" data-rstk-edit-type="video" data-rstk-label="${escapeHtml(label)}" data-rstk-edit-id="${escapeHtml(editId)}" data-rstk-video-url="${escapeHtml(videoSource)}" data-rstk-video-settings="${escapeHtml(jsonString(settings))}" style="width:100%;aspect-ratio:16/9;min-height:220px;overflow:hidden;background:#000;border-radius:inherit;">${renderedVideo}</div>`
  }

  let nextOpeningTag = setHtmlAttribute(openingTag, attrsText, 'data-rstk-video-url', videoSource)
  nextOpeningTag = setHtmlAttribute(nextOpeningTag, attrsText, 'data-rstk-video-settings', jsonString(settings))
  return `${nextOpeningTag}${renderedVideo}</${tagName}>`
}

function rewriteImportedVideosForRender(site, html = '', context = {}) {
  const source = String(html || '')
  if (!/data-rstk-edit-type\s*=\s*(?:"video"|'video'|video)|data-ristak-edit-type\s*=\s*(?:"video"|'video'|video)|data-ristack-edit-type\s*=\s*(?:"video"|'video'|video)/i.test(source)) {
    return source
  }

  const openingPattern = /<([a-z][\w:-]*)\b([^>]*)>/gi
  let cursor = 0
  let index = 0
  let output = ''
  let match

  while ((match = openingPattern.exec(source))) {
    if (match.index < cursor) continue
    const tagName = match[1] || ''
    const attrsText = match[2] || ''
    if (getImportedEditTypeFromAttrs(attrsText) !== 'video') continue

    const openingTag = match[0] || ''
    const openEnd = openingPattern.lastIndex
    const selfClosing = isImportedHtmlSelfClosingTag(tagName, openingTag)
    const end = selfClosing ? openEnd : findImportedHtmlElementEnd(source, tagName, openEnd)
    if (end < openEnd) continue

    const originalHtml = source.slice(match.index, end)
    const replacement = renderImportedVideoElementForRender({
      sourceHtml: originalHtml,
      tagName,
      openingTag,
      attrsText,
      selfClosing,
      site,
      context,
      index
    })

    output += source.slice(cursor, match.index)
    output += replacement
    cursor = end
    openingPattern.lastIndex = end
    index += 1
  }

  return cursor ? `${output}${source.slice(cursor)}` : source
}

