export async function sendCalendarBookingSiteMetaEvent({ calendar, appointment, contactId, contact = {}, requestMeta = {}, siteOverride = null }) {
  const config = getCalendarSiteMetaEventConfig(calendar, siteOverride)
  const eventId = `calendar_${cleanString(calendar?.id) || 'unknown'}_${cleanString(appointment?.id) || crypto.randomUUID()}`

  // Snapshot de atribución interna de la cita (último paid touch + superficie
  // website: el booking ocurrió en la página/widget). Se guarda aunque el
  // envío a Meta se salte más abajo.
  if (contactId && cleanString(appointment?.id)) {
    const conversionResolution = await resolveConversionAttribution({
      contactId,
      conversionType: 'appointment',
      conversionSurface: 'website'
    }).catch(error => {
      logger.warn(`No se pudo resolver atribución de conversión para cita ${appointment?.id}: ${error.message}`)
      return null
    })
    if (conversionResolution) {
      await persistAppointmentConversionAttribution(cleanString(appointment.id), conversionResolution)
    }
  }

  const testModeActive = await isMetaTestModeActive()
  if (shouldSkipTracking({ meta: requestMeta?.meta }) && !testModeActive) {
    return { sent: false, reason: NO_TRACK_REASON, eventId, eventName: config.eventName }
  }

  if (!config.enabled) {
    return { sent: false, reason: 'disabled', eventId, eventName: config.eventName }
  }

  if (!['site', 'smart'].includes(config.channel)) {
    return { sent: false, reason: 'channel_not_site', eventId, eventName: config.eventName }
  }

  if (config.eventName === SITE_META_NO_EVENT) {
    return { sent: false, reason: 'no_event_configured', eventId, eventName: config.eventName }
  }

  const metaConfig = await getMetaConfig().catch(error => {
    logger.warn(`No se pudo leer configuración Meta para calendario CAPI: ${error.message}`)
    return null
  })
  const datasetId = cleanString(metaConfig?.pixel_id || process.env.META_PIXEL_ID || process.env.META_DATASET_ID)
  const accessToken = cleanString(resolveMetaCapiAccessToken(metaConfig))

  if (!datasetId || !accessToken) {
    await logMetaEvent({
      contactId,
      eventType: 'calendar_appointment_booked',
      metaEventName: config.eventName,
      eventId,
      status: 'skipped',
      errorMessage: 'Falta Pixel/Dataset ID o System User Access Token de Meta'
    })
    return { sent: false, reason: 'missing_meta_config', eventId, eventName: config.eventName }
  }

  const templateContact = await loadContactForMetaTemplate(contactId, contact)
  const fullName = cleanString(templateContact.fullName || templateContact.full_name || templateContact.name)
  const names = splitName(fullName)
  const sourceUrl = getMetaSourceUrlFromRequestMeta(requestMeta)
  const signals = collectMetaParameterSignals({
    req: requestMeta?.req,
    requestMeta,
    sourceUrl
  })
  const userData = buildMetaParameterUserData({
    req: requestMeta?.req,
    requestMeta,
    contact: {
      ...templateContact,
      fullName,
      id: contactId
    },
    names,
    externalId: contactId,
    sourceUrl,
    collectedSignals: signals
  })

  if (!userData.em && !userData.ph && !userData.external_id && !userData.fbp && !userData.fbc) {
    await logMetaEvent({
      contactId,
      eventType: 'calendar_appointment_booked',
      metaEventName: config.eventName,
      eventId,
      status: 'skipped',
      errorMessage: 'user_data insuficiente para Meta'
    })
    return { sent: false, reason: 'insufficient_user_data', eventId, eventName: config.eventName }
  }

  const accountLocale = await getAccountLocaleSettings().catch(() => null)
  const variableFields = await getVariableFieldValueMap().catch(() => ({}))
  const templateContext = buildSiteMetaTemplateContext({
    site: siteOverride || {},
    page: null,
    contact: templateContact,
    contactId,
    requestMeta,
    accountCurrency: accountLocale?.currency || 'MXN',
    appointment,
    calendar,
    variableFields
  })
  const customData = mergeSiteMetaCustomData(
    buildCalendarMetaBaseCustomData(calendar, appointment, { currency: accountLocale?.currency || 'MXN' }),
    buildSiteMetaConfiguredCustomData(config.parameters, config.eventName, templateContext)
  )
  const payload = {
    data: [
      {
        event_name: config.eventName,
        event_time: Math.floor(Date.now() / 1000),
        action_source: 'website',
        ...buildMetaEventUrlFields(signals, sourceUrl),
        event_id: eventId,
        user_data: userData,
        custom_data: customData
      }
    ]
  }

  const testEventCode = await getActiveMetaTestEventCode()
  if (testEventCode) {
    payload.test_event_code = testEventCode
  }

  try {
    const response = await fetch(buildMetaCapiRequestUrl(datasetId, accessToken, metaConfig), {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    })
    const responsePayload = await response.json().catch(() => ({}))

    if (!response.ok || responsePayload?.error) {
      throw new Error(describeMetaCapiResponseError(responsePayload, response.status))
    }

    await logMetaEvent({
      contactId,
      eventType: 'calendar_appointment_booked',
      metaEventName: config.eventName,
      eventId,
      status: 'success',
      requestPayload: payload,
      responsePayload
    })

    // Marca el dedup de agenda a nivel contacto: si más tarde llega un echo
    // (webhook GHL de la misma cita) por el trigger de business_messaging,
    // el flag evita una SEGUNDA conversión con otro event_id.
    // En modo test no marcamos la bandera: una cita de prueba no debe bloquear
    // el evento real (ni el re-test) de ese mismo contacto.
    if (contactId && !testModeActive) {
      await db.run(
        `UPDATE contacts
         SET meta_schedule_event_sent = 1,
             meta_schedule_event_sent_at = CURRENT_TIMESTAMP,
             meta_schedule_event_id = ?,
             updated_at = CURRENT_TIMESTAMP
         WHERE id = ?`,
        [eventId, contactId]
      ).catch(error => {
        logger.warn(`No se pudo marcar meta_schedule_event_sent para contacto ${contactId}: ${error.message}`)
      })
    }

    return {
      sent: true,
      eventId,
      eventName: config.eventName,
      appointmentId: appointment?.id || '',
      status: customData.appointment_status || 'booked',
      responsePayload
    }
  } catch (error) {
    const safeError = safeMetaGraphTransportError(error)
    await logMetaEvent({
      contactId,
      eventType: 'calendar_appointment_booked',
      metaEventName: config.eventName,
      eventId,
      status: 'error',
      requestPayload: payload,
      errorMessage: safeError
    })
    return { sent: false, reason: 'meta_error', error: safeError, eventId, eventName: config.eventName }
  }
}

async function sendSiteVideoActionMetaEvent({ site, block, rule, eventName, parameters, eventId, contactId, requestMeta }) {
  const testModeActive = await isMetaTestModeActive()
  if (shouldSkipTracking({ meta: requestMeta?.meta }) && !testModeActive) {
    return { sent: false, reason: NO_TRACK_REASON, eventId, eventName }
  }

  const metaConfig = await getMetaConfig().catch(error => {
    logger.warn(`No se pudo leer configuración Meta para acción de video Site: ${error.message}`)
    return null
  })
  const datasetId = cleanString(metaConfig?.pixel_id || process.env.META_PIXEL_ID || process.env.META_DATASET_ID)
  const accessToken = cleanString(resolveMetaCapiAccessToken(metaConfig))

  if (!datasetId || !accessToken) {
    await logMetaEvent({
      contactId,
      eventType: 'site_video_action',
      metaEventName: eventName,
      eventId,
      status: 'skipped',
      errorMessage: 'Falta Pixel/Dataset ID o System User Access Token de Meta'
    })
    return { sent: false, reason: 'missing_meta_config', eventId, eventName }
  }

  const eventTimeMs = resolveMetaEventTimeMs(requestMeta)
  const { sourceUrl, signals } = collectSiteMetaSignals(site, requestMeta)
  const userData = buildMetaBaseUserData({ contactId, requestMeta, eventTimeMs, sourceUrl, signals })

  if (!userData.client_ip_address && !userData.client_user_agent && !userData.fbp && !userData.fbc && !userData.external_id) {
    await logMetaEvent({
      contactId,
      eventType: 'site_video_action',
      metaEventName: eventName,
      eventId,
      status: 'skipped',
      errorMessage: 'user_data insuficiente para Meta'
    })
    return { sent: false, reason: 'insufficient_user_data', eventId, eventName }
  }

  const pageId = cleanString(requestMeta.meta?.pageId || requestMeta.meta?.page_id)
  const page = getSitePage(site, pageId)
  const accountLocale = await getAccountLocaleSettings().catch(() => null)
  const variableFields = await getVariableFieldValueMap().catch(() => ({}))
  const templateContact = await loadContactForMetaTemplate(contactId, {})
  const templateContext = buildSiteMetaTemplateContext({
    site,
    page,
    contact: templateContact,
    contactId,
    requestMeta,
    accountCurrency: accountLocale?.currency || 'MXN',
    variableFields
  })
  const payload = {
    data: [
      {
        event_name: eventName,
        event_time: Math.floor(eventTimeMs / 1000),
        action_source: 'website',
        ...buildMetaEventUrlFields(signals, sourceUrl),
        event_id: eventId,
        user_data: userData,
        custom_data: mergeSiteMetaCustomData({
          source: 'ristak_site',
          conversion_type: 'video_action',
          site_id: site.id,
          site_name: site.name,
          public_page_id: page?.id || pageId,
          public_page_title: page?.title || '',
          video_block_id: block?.id || '',
          video_block_label: block?.label || '',
          video_action_id: rule?.id || '',
          // La configuración guardada del Site es la fuente confiable. No
          // aceptamos que el navegador fabrique el tipo/umbral del evento.
          video_action_time_seconds: Number(rule?.timeSeconds || 0) || 0,
          video_action_trigger_type: normalizeVideoActionTriggerType(rule?.triggerType),
          video_action_trigger_value: normalizeVideoActionTriggerValue(rule?.triggerValue, normalizeVideoActionTriggerType(rule?.triggerType)),
          currency: accountLocale?.currency || 'MXN',
          content_name: block?.label || page?.title || site.title || site.name
        }, buildSiteMetaConfiguredCustomData(parameters, eventName, templateContext))
      }
    ]
  }

  const testEventCode = await getActiveMetaTestEventCode()
  if (testEventCode) {
    payload.test_event_code = testEventCode
  }

  try {
    const response = await fetch(buildMetaCapiRequestUrl(datasetId, accessToken, metaConfig), {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    })
    const responsePayload = await response.json().catch(() => ({}))

    if (!response.ok || responsePayload?.error) {
      throw new Error(describeMetaCapiResponseError(responsePayload, response.status))
    }

    await logMetaEvent({
      contactId,
      eventType: 'site_video_action',
      metaEventName: eventName,
      eventId,
      status: 'success',
      requestPayload: payload,
      responsePayload
    })

    return { sent: true, eventId, eventName, responsePayload }
  } catch (error) {
    const safeError = safeMetaGraphTransportError(error)
    await logMetaEvent({
      contactId,
      eventType: 'site_video_action',
      metaEventName: eventName,
      eventId,
      status: 'error',
      requestPayload: payload,
      errorMessage: safeError
    })
    return { sent: false, reason: 'meta_error', error: safeError, eventId, eventName }
  }
}

async function recordNativeSiteConversionEvent({ site, blocks, submittedPageId, submissionId, contactId, contact, req, meta }) {
  if (shouldSkipTracking({ req, meta })) return

  const visitorId = cleanString(meta?.visitorId || meta?.visitor_id) || `site_visitor_${submissionId}`
  const sessionId = cleanString(meta?.sessionId || meta?.session_id) || `site_session_${submissionId}`
  const tracking = meta?.tracking && typeof meta.tracking === 'object' ? meta.tracking : {}
  const importedConversionMeta = normalizeImportedHtmlConversionMeta(meta)
  const importedConversionData = importedConversionMeta
    ? buildImportedHtmlConversionBaseCustomData(importedConversionMeta, site, {
      status: importedConversionMeta.status || (meta?.formDisqualified || meta?.form_disqualified ? 'disqualified' : '')
    })
    : {}
  const pages = normalizeSitePages(site)
  const page = pages.find(item => item.id === submittedPageId) || pages[0] || null
  const formContext = getNativeFormContext(site, blocks)
  const explicitFormSiteId = cleanString(meta?.formSiteId || meta?.form_site_id)
  const explicitFormSiteName = cleanString(meta?.formSiteName || meta?.form_site_name)

  const data = {
    ...tracking,
    ...importedConversionData,
    tracking_source: 'native_site',
    site_id: site.id,
    site_slug: site.slug,
    site_name: site.name,
    site_type: site.siteType,
    form_site_id: explicitFormSiteId || formContext.formSiteId,
    form_site_name: explicitFormSiteName || formContext.formSiteName,
    public_page_id: submittedPageId || page?.id || '',
    public_page_title: page?.title || '',
    conversion_type: importedConversionMeta?.conversionType || 'form_submit',
    submission_id: submissionId,
    url: cleanString(meta?.pageUrl) || tracking.url || `https://${site.domain || cleanString(meta?.host) || ''}`,
    referrer: cleanString(meta?.referrer) || tracking.referrer || null,
    contact_name: cleanString(contact?.fullName) || undefined
  }

  await createSession({
    session_id: sessionId,
    visitor_id: visitorId,
    contact_id: contactId || null,
    full_name: cleanString(contact?.fullName) || null,
    event_name: 'native_site_conversion',
    ts: Date.now(),
    data,
    ip: getClientIp(req),
    user_agent: req.headers['user-agent'] || ''
  })

  if (contactId) {
    linkVisitorToContact(visitorId, contactId, cleanString(contact?.fullName) || 'Lead de site')
      .then(() => unifyVisitorIds(contactId))
      .catch(error => {
        logger.warn(`No se pudo vincular visitor nativo ${visitorId} con contacto ${contactId}: ${error.message}`)
      })
  }
}

function isEmptyImportedValue(value) {
  if (Array.isArray(value)) return value.length === 0
  return !cleanString(value)
}

function normalizeImportedValue(value) {
  if (Array.isArray(value)) {
    return value.map(item => cleanString(item)).filter(Boolean)
  }

  if (value && typeof value === 'object') {
    return jsonString(value)
  }

  return cleanString(value)
}

function normalizeImportedRawFields(rawFields = {}) {
  if (!rawFields || typeof rawFields !== 'object' || Array.isArray(rawFields)) return {}

  return Object.entries(rawFields).reduce((acc, [key, value]) => {
    const rawKey = cleanString(key)
    if (!rawKey) return acc
    const normalizedValue = normalizeImportedValue(value)
    if (isEmptyImportedValue(normalizedValue)) return acc
    acc[rawKey] = normalizedValue
    return acc
  }, {})
}

function getImportedFormMapping(imported, formId, { allowSingleLegacyFallback = false } = {}) {
  const mappings = Array.isArray(imported?.formMappings)
    ? imported.formMappings.filter(mapping => (
      mapping?.present !== false && !isImportedRuntimeAmbiguousFormMapping(mapping)
    ))
    : []
  if (!mappings.length) return null

  const requested = normalizeImportedFieldKey(formId, '')
  const matches = mappings.filter(mapping => normalizeImportedFieldKey(mapping.formId, '') === requested)
  if (matches.length === 1) return matches[0]
  if (allowSingleLegacyFallback && mappings.length === 1) return mappings[0]
  return null
}

function getImportedRawFieldValue(rawFields = {}, mapping = {}) {
  // En el contrato moderno el ID estable es también la llave del payload. No
  // aceptamos name/destinationKey como alias porque permitiría que dos campos
  // distintos con el mismo name se pisen o que un raw key evada su asociación.
  const directKeys = mapping?.hasStableFieldId === true
    ? [mapping.fieldId].map(cleanString).filter(Boolean)
    : [mapping.sourceName, mapping.fieldId, mapping.destinationKey].map(cleanString).filter(Boolean)

  for (const key of directKeys) {
    if (Object.prototype.hasOwnProperty.call(rawFields, key)) {
      return { key, value: rawFields[key] }
    }
  }

  const normalizedLookup = new Map(
    Object.keys(rawFields).map(key => [normalizeImportedFieldKey(key, ''), key])
  )

  for (const key of directKeys) {
    const foundKey = normalizedLookup.get(normalizeImportedFieldKey(key, ''))
    if (foundKey) return { key: foundKey, value: rawFields[foundKey] }
  }

  return { key: '', value: null }
}

function inferImportedDataType(mapping = {}, value = '') {
  const type = normalizeImportedFieldKey(mapping.customFieldDataType || mapping.custom_field_data_type || mapping.type || mapping.dataType, '')
  if (type === 'textarea') return 'textarea'
  if (type === 'select') return Array.isArray(value) ? 'multiselect' : 'select'
  if (['radio', 'dropdown'].includes(type)) return 'select'
  if (['checkbox', 'checkboxes'].includes(type)) return 'multiselect'
  if (['number', 'currency', 'date', 'time', 'email', 'phone'].includes(type)) return type
  if (Array.isArray(value)) return 'multiselect'
  return 'text'
}

function addImportedCustomField(customFields, field = {}, value, context = {}) {
  const definitionId = cleanString(
    field.customFieldDefinitionId ||
    field.custom_field_definition_id ||
    field.definitionId ||
    field.definition_id ||
    field.customFieldId ||
    field.custom_field_id
  )
  const key = normalizeImportedFieldKey(
    field.customFieldKey ||
    field.custom_field_key ||
    field.fieldKey ||
    field.field_key ||
    field.destinationKey ||
    field.key ||
    field.sourceName ||
    field.label,
    'custom_field'
  )
  if (!key || isEmptyImportedValue(value)) return
  const label = cleanString(field.customFieldLabel || field.custom_field_label || field.label) || key
  const dataType = cleanString(field.customFieldDataType || field.custom_field_data_type) || inferImportedDataType(field, value)

  customFields.push({
    id: definitionId || key,
    definitionId,
    key,
    fieldKey: key,
    label,
    name: label,
    dataType,
    options: Array.isArray(field.options) ? field.options : [],
    value,
    syncTarget: cleanString(field.customFieldSyncTarget || field.custom_field_sync_target || field.syncTarget || field.sync_target || 'local'),
    sourceType: 'imported_html',
    sourceId: context.importId || '',
    sourceSiteId: context.siteId || '',
    sourcePageId: DEFAULT_FUNNEL_PAGE_ID,
    sourceFormId: context.formId || '',
    sourceFormName: context.formTitle || '',
    sourceFieldId: cleanString(field.fieldId || field.id),
    sourceFieldName: cleanString(field.sourceName || field.name),
    sourceLabel: cleanString(field.label),
    sourceContext: {
      originalFilename: context.originalFilename || '',
      confidence: field.confidence ?? null,
      imported: true
    }
  })
}

function buildImportedSubmissionLayers({ site, imported, formId, rawFields, allowSingleLegacyFallback = false }) {
  const formMapping = getImportedFormMapping(imported, formId, { allowSingleLegacyFallback })
  const mappedFields = {
    standard: {},
    custom: {},
    ignored: {}
  }
  const derivedFields = {}
  const customFields = []
  const consumedRawKeys = new Set()
  const acceptedRawFields = {}
  const allFormFields = Array.isArray(formMapping?.fields) ? formMapping.fields : []
  const hasStableMappingContract = formMapping?.hasStableFormId === true ||
    allFormFields.some(field => field?.hasStableFieldId === true)
  const context = {
    importId: imported?.id || '',
    siteId: site.id,
    formId: formMapping?.formId || formId || 'form_1',
    formTitle: formMapping?.formTitle || 'Formulario importado',
    originalFilename: imported?.originalFilename || ''
  }

  // Una llave de un campo removido no puede reaparecer como campo inferido. Se
  // reconoce como tombstone y se descarta antes de procesar compatibilidad legacy.
  for (const field of allFormFields.filter(item => item?.present === false)) {
    const { key: rawKey } = getImportedRawFieldValue(rawFields, field)
    if (rawKey) consumedRawKeys.add(rawKey)
  }

  for (const field of allFormFields.filter(item => item?.present !== false)) {
    const { key: rawKey, value } = getImportedRawFieldValue(rawFields, field)
    if (!rawKey || isEmptyImportedValue(value)) continue

    consumedRawKeys.add(rawKey)
    acceptedRawFields[rawKey] = value
    const destinationType = field.ignored ? 'ignored' : cleanString(field.destinationType || field.saveMode || 'custom')
    const destinationKey = normalizeImportedFieldKey(field.destinationKey || field.sourceName || rawKey, 'custom_field')

    if (destinationType === 'ignored') {
      mappedFields.ignored[rawKey] = value
      continue
    }

    if (destinationType === 'standard' && IMPORTED_FORM_STANDARD_FIELDS.has(destinationKey)) {
      mappedFields.standard[destinationKey] = value
      continue
    }

    mappedFields.custom[destinationKey] = value
    addImportedCustomField(customFields, { ...field, destinationKey }, value, context)
  }

  for (const [rawKey, value] of Object.entries(rawFields)) {
    if (consumedRawKeys.has(rawKey) || isEmptyImportedValue(value)) continue
    // Formularios con IDs estables son allowlist estricta: solo viajan las
    // llaves detectadas y mapeadas. El fallback existe únicamente para HTML
    // legacy que todavía no tiene data-rstk-form-id/data-rstk-field-id.
    if (hasStableMappingContract) continue
    acceptedRawFields[rawKey] = value
    const key = normalizeImportedFieldKey(rawKey, 'custom_field')
    const fallbackField = {
      destinationKey: key,
      sourceName: rawKey,
      name: rawKey,
      label: rawKey,
      type: Array.isArray(value) ? 'checkboxes' : 'text'
    }
    const inferred = inferImportedFieldDestination(fallbackField)

    if (inferred.destinationType === 'standard' && IMPORTED_FORM_STANDARD_FIELDS.has(inferred.destinationKey)) {
      mappedFields.standard[inferred.destinationKey] = value
      continue
    }

    const destinationKey = inferred.destinationType === 'custom' ? inferred.destinationKey : key
    mappedFields.custom[destinationKey] = value
    addImportedCustomField(customFields, {
      ...fallbackField,
      destinationKey,
      confidence: inferred.confidence
    }, value, context)
  }

  if (mappedFields.standard.full_name) {
    const names = splitName(mappedFields.standard.full_name)
    if (names.firstName && !mappedFields.standard.first_name) derivedFields.first_name = names.firstName
    if (names.lastName && !mappedFields.standard.last_name) derivedFields.last_name = names.lastName
  }

  if (!mappedFields.standard.full_name && (mappedFields.standard.first_name || mappedFields.standard.last_name)) {
    derivedFields.full_name = [mappedFields.standard.first_name, mappedFields.standard.last_name].map(cleanString).filter(Boolean).join(' ')
  }

  if (mappedFields.standard.email) {
    derivedFields.email = normalizeEmail(mappedFields.standard.email)
  }

  if (mappedFields.standard.phone) {
    derivedFields.phone = cleanString(mappedFields.standard.phone)
  }

  return {
    formMapping,
    rawFields: hasStableMappingContract ? acceptedRawFields : rawFields,
    mappedFields,
    derivedFields,
    customFields
  }
}

async function upsertImportedContactFromSubmission({ site, contact, customFields, meta, imported, formMapping }) {
  const contactResult = await upsertContactFromSubmissionWithResult({ site, contact, meta })
  const contactId = contactResult.contactId
  if (!contactId || !Array.isArray(customFields) || customFields.length === 0) return contactResult

  const preparedFields = await prepareContactCustomFieldsForStorage(customFields, {
    sourceType: 'imported_html',
    sourceId: imported?.id || '',
    sourceSiteId: site.id,
    sourcePageId: DEFAULT_FUNNEL_PAGE_ID,
    sourceFormId: formMapping?.formId || meta?.importedFormId || '',
    sourceFormName: formMapping?.formTitle || '',
    syncTarget: 'local'
  })
  const existing = await db.get('SELECT custom_fields FROM contacts WHERE id = ?', [contactId])
  const merged = mergeContactCustomFields(
    parseContactCustomFields(existing?.custom_fields),
    preparedFields
  )

  await db.run(`
    UPDATE contacts SET
      custom_fields = ${process.env.DATABASE_URL ? '?::jsonb' : '?'},
      updated_at = CURRENT_TIMESTAMP
    WHERE id = ?
  `, [
    serializeContactCustomFieldsForDb(merged),
    contactId
  ])

  return {
    ...contactResult,
    changedFields: [
      ...(contactResult.changedFields || []),
      ...customFieldChangeKeys(preparedFields)
    ]
  }
}

async function createImportedSubmissionFromRequest({ req, body, site, host, previewContext = null }) {
  const imported = await getImportedSiteBySiteId(site.id)
  if (!imported) {
    const error = new Error('Importacion de HTML no encontrada')
    error.status = 404
    throw error
  }

  const submittedFormId = cleanString(body.importedFormId || body.imported_form_id || body.formId || body.form_id)
  const importedFormId = submittedFormId || 'form_1'
  const rawFields = normalizeImportedRawFields(body.rawFields || body.raw_fields || body.responses || {})
  const layers = buildImportedSubmissionLayers({
    site,
    imported,
    formId: importedFormId,
    rawFields,
    allowSingleLegacyFallback: !submittedFormId
  })
  const activeFormMappings = Array.isArray(imported.formMappings)
    ? imported.formMappings.filter(mapping => mapping?.present !== false)
    : []
  if (!layers.formMapping) {
    const error = new Error('El formulario enviado no coincide con una zona HTML configurada')
    error.status = 400
    throw error
  }
  const standard = layers.mappedFields.standard || {}
  const derived = layers.derivedFields || {}
  const contactNameFields = normalizeContactNameFields({
    fullName: standard.full_name || derived.full_name,
    firstName: standard.first_name || derived.first_name,
    lastName: standard.last_name || derived.last_name
  })
  const fullName = contactNameFields.fullName
  const rawPhone = standard.phone || derived.phone
  const contact = {
    fullName,
    email: normalizeEmail(standard.email || derived.email),
    phone: await normalizePhoneForAccount(rawPhone) || cleanString(rawPhone)
  }
  const meta = {
    ...(body.meta && typeof body.meta === 'object' ? body.meta : {}),
    host,
    previewSession: Boolean(previewContext),
    previewPageId: previewContext?.pageId || '',
    importedHtml: true,
    importedFormId: layers.formMapping?.formId || importedFormId,
    importedFormTitle: layers.formMapping?.formTitle || '',
    formSiteId: getImportedFormMappingSourceSiteId(layers.formMapping),
    formSiteName: layers.formMapping?.formTitle || '',
    userAgent: req.headers['user-agent'] || '',
    submittedAt: new Date().toISOString()
  }
  const importedDisqualified = meta.importedDisqualified === true || meta.imported_disqualified === true
  const submissionStatus = importedDisqualified ? 'disqualified' : 'received'
  const responseMessage = importedDisqualified
    ? cleanString(meta.importedDisqualifiedMessage || meta.imported_disqualified_message) || 'Gracias. Por ahora esta solicitud no califica.'
    : 'Listo. Recibimos tu información.'
  if (shouldSkipTracking({ req, body, meta, previewContext }) && (Boolean(previewContext) || !(await isMetaTestModeActive()))) {
    return {
      submissionId: createRistakId('site_preview_submission'),
      siteId: site.id,
      contactId: null,
      contactName: contact.fullName,
      contactEmail: contact.email,
      contactPhone: contact.phone,
      status: submissionStatus,
      message: responseMessage,
      rawFields: layers.rawFields,
      mappedFields: layers.mappedFields,
      derivedFields: layers.derivedFields,
      preview: true,
      skipped: true,
      capi: { sent: false, reason: NO_TRACK_REASON }
    }
  }

  const contactResult = await upsertImportedContactFromSubmission({
    site,
    contact,
    customFields: layers.customFields,
    meta,
    imported,
    formMapping: layers.formMapping
  })
  const contactId = contactResult.contactId
  const submissionId = createRistakId('site_submission')
  const importedAutomationFormId = layers.formMapping?.formId || importedFormId
  const importedAutomationFormName = layers.formMapping?.formTitle || site.name || ''
  const importedSourceFormSiteId = getImportedFormMappingSourceSiteId(layers.formMapping)
  const automationFormResponses = buildImportedAutomationFormResponses({
    rawFields: layers.rawFields,
    mappedFields: layers.mappedFields
  })

  Object.assign(meta, {
    submissionId,
    formStatus: submissionStatus,
    formDisqualified: submissionStatus === 'disqualified',
    formResponses: automationFormResponses,
    rawFields: layers.rawFields,
    mappedFields: layers.mappedFields,
    derivedFields: layers.derivedFields
  })

  await db.run(`
    INSERT INTO public_site_submissions (
      id, site_id, form_site_id, contact_id, domain, response_json, raw_fields_json,
      mapped_fields_json, derived_fields_json, meta_json, status, created_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
  `, [
    submissionId,
    site.id,
    importedSourceFormSiteId || null,
    contactId,
    host,
    jsonString(layers.mappedFields),
    jsonString(layers.rawFields),
    jsonString(layers.mappedFields),
    jsonString(layers.derivedFields),
    jsonString(meta),
    submissionStatus
  ])

  await emitSiteSubmissionAutomationEvents({
    contactResult,
    formEvent: {
      contactId,
      formId: importedSourceFormSiteId || site.id,
      formName: importedAutomationFormName,
      automationFormId: automationImportedFormId(site.id, importedAutomationFormId),
      siteId: site.id,
      siteName: site.name || '',
      formSiteId: importedSourceFormSiteId || null,
      formSiteName: importedAutomationFormName,
      importedFormId: importedAutomationFormId,
      importedFormName: importedAutomationFormName,
      submissionId,
      formStatus: submissionStatus,
      status: submissionStatus,
      formDisqualified: submissionStatus === 'disqualified',
      submittedAt: meta.submittedAt,
      formResponses: automationFormResponses
    },
    contactChangedFields: customFieldChangeKeys(layers.customFields)
  })
  const latestContactForMeta = await loadContactForMetaTemplate(contactId, contact)

  const capi = await sendSiteLeadMetaEvent({
    site,
    submissionId,
    submittedPageId: DEFAULT_FUNNEL_PAGE_ID,
    contactId,
    contact: latestContactForMeta,
    requestMeta: {
      req,
      ip: getClientIp(req),
      userAgent: req.headers['user-agent'] || '',
      meta
    }
  })

  await recordNativeSiteConversionEvent({
    site,
    blocks: [],
    submittedPageId: DEFAULT_FUNNEL_PAGE_ID,
    submissionId,
    contactId,
    contact,
    req,
    meta
  }).catch(error => {
    logger.warn(`No se pudo registrar conversion nativa de HTML importado ${site.id}: ${error.message}`)
  })

  const responseContact = buildPublicContactPayload(contactId, contact)

  return {
    submissionId,
    siteId: site.id,
    contactId,
    contact: responseContact,
    contactName: responseContact.fullName,
    contactEmail: responseContact.email,
    contactPhone: responseContact.phone,
    status: submissionStatus,
    message: responseMessage,
    rawFields: layers.rawFields,
    mappedFields: layers.mappedFields,
    derivedFields: layers.derivedFields,
    capi
  }
}

function findEnabledPaymentBlockContext(blocks = [], site = {}, parentBlockId = '') {
  const items = Array.isArray(blocks) ? blocks : []
  const pages = normalizeSitePages(site)

  for (const block of items) {
    if (!block || typeof block !== 'object') continue
    if (isPaymentBlockEnabled(block)) {
      const paymentGate = getPaymentGateFromBlock(block)
      return {
        block,
        blockId: cleanString(block.id),
        parentBlockId: cleanString(parentBlockId),
        blockPageId: getBlockPageId(block, pages),
        paymentGate
      }
    }

    const settings = block.settings || {}
    if (Array.isArray(settings.embeddedBlocks)) {
      const nested = findEnabledPaymentBlockContext(settings.embeddedBlocks, site, block.id)
      if (nested) return nested
    }
  }

  return null
}

function withPaymentBlockMetadata(paymentGate = {}, context = {}) {
  return {
    ...paymentGate,
    blockId: context.blockId || '',
    blockPageId: context.blockPageId || '',
    parentBlockId: context.parentBlockId || ''
  }
}

// Igual que findEnabledPaymentBlockContext pero busca un bloque de pago ESPECÍFICO por
// id (una página puede tener varios). Si no se pasa id, devuelve el primero habilitado.
// Recorre también bloques embebidos (formularios dentro de landings).
function findEnabledPaymentBlockById(blocks = [], site = {}, blockId = '', parentBlockId = '') {
  const items = Array.isArray(blocks) ? blocks : []
  const pages = normalizeSitePages(site)
  const wanted = cleanString(blockId)

  for (const block of items) {
    if (!block || typeof block !== 'object') continue
    if ((!wanted || cleanString(block.id) === wanted) && isPaymentBlockEnabled(block)) {
      return {
        block,
        blockId: cleanString(block.id),
        parentBlockId: cleanString(parentBlockId),
        blockPageId: getBlockPageId(block, pages),
        paymentGate: getPaymentGateFromBlock(block)
      }
    }

    const settings = block.settings || {}
    if (Array.isArray(settings.embeddedBlocks)) {
      const nested = findEnabledPaymentBlockById(settings.embeddedBlocks, site, wanted, block.id)
      if (nested) return nested
    }
  }

  return null
}

function validatePaymentBlockRequestContext(context = {}, { blockId = '', pageId = '' } = {}) {
  const requestedBlockId = cleanString(blockId)
  const requestedPageId = cleanString(pageId)
  const contextBlockId = cleanString(context.blockId)
  const contextPageId = cleanString(context.blockPageId)

  if (!requestedBlockId) {
    const error = new Error('Falta identificar el bloque de pago.')
    error.status = 400
    throw error
  }
  if (contextBlockId !== requestedBlockId) {
    const error = new Error('El bloque de pago no pertenece a este site.')
    error.status = 404
    throw error
  }
  if (requestedPageId && contextPageId && requestedPageId !== contextPageId) {
    const error = new Error('El bloque de pago no pertenece a la pagina solicitada.')
    error.status = 409
    throw error
  }
}

function resolveSitePaymentGateConfig(site = {}, contexts = {}) {
  const blockCandidates = [
    contexts.submissionBlocks,
    contexts.videoFormGateContext?.blocks,
    contexts.landingEmbeddedFormContext?.blocks,
    contexts.defaultSubmissionBlocks,
    contexts.allBlocks
  ]

  for (const blocks of blockCandidates) {
    const context = findEnabledPaymentBlockContext(blocks, site)
    if (context?.paymentGate) return withPaymentBlockMetadata(context.paymentGate, context)
  }

  const candidates = [
    contexts.videoFormGateContext?.formTheme,
    contexts.landingEmbeddedFormContext?.formTheme,
    site.theme
  ]

  for (const candidate of candidates) {
    const normalized = normalizePaymentGateConfig(candidate || {})
    if (isPaymentGateEnabled(normalized)) return normalized
  }

  return normalizePaymentGateConfig(site.theme || {})
}

function getBodyPaymentPublicId(body = {}) {
  return cleanString(
    body.paymentPublicId ||
    body.payment_public_id ||
    body.publicPaymentId ||
    body.public_payment_id ||
    body.meta?.paymentPublicId ||
    body.meta?.payment_public_id ||
    body.meta?.publicPaymentId ||
    body.meta?.public_payment_id
  )
}

function shouldRequireSitePaymentGate({ site, paymentGate, ruleEvaluation, isRuleSubmit, isFinalStandardFormSubmit, submittedPageId }) {
  if (!isPaymentGateEnabled(paymentGate)) return false
  if (ruleEvaluation?.status === 'disqualified' || ruleEvaluation?.disqualified === true) return false
  if (isRuleSubmit) return false
  const paymentPageId = cleanString(paymentGate.blockPageId)
  const currentPageId = cleanString(submittedPageId)
  const isNestedPaymentBlock = Boolean(cleanString(paymentGate.parentBlockId))
  const topLevelPaymentBlockIsOnAnotherPage = Boolean(
    paymentPageId &&
    currentPageId &&
    paymentPageId !== currentPageId &&
    !isNestedPaymentBlock
  )
  if (site.siteType === 'standard_form') {
    if (paymentPageId && currentPageId && paymentPageId === currentPageId) return true
    return Boolean(isFinalStandardFormSubmit)
  }
  if (topLevelPaymentBlockIsOnAnotherPage) return false
  return site.siteType === 'interactive_form' || site.siteType === 'landing_page'
}

function paymentGateMatchesAnySiteContext(status, expected = {}) {
  const gate = status?.metadata?.paymentGate && typeof status.metadata.paymentGate === 'object'
    ? status.metadata.paymentGate
    : {}
  const matchKey = (key) => cleanString(gate[key] || status?.metadata?.[key])
  const expectedPageIds = [
    expected.pageId,
    expected.submittedPageId,
    expected.blockPageId
  ].map(cleanString).filter(Boolean)
  const actualPageIds = [
    gate.pageId,
    gate.submittedPageId,
    gate.blockPageId,
    status?.metadata?.pageId,
    status?.metadata?.submittedPageId,
    status?.metadata?.blockPageId
  ].map(cleanString).filter(Boolean)
  // Solo se validan las claves presentes en expected: así un pago hecho por el checkout
  // embebido inline (source 'site_checkout') satisface un gate de formulario del mismo
  // sitio+bloque. La vigencia de monto/moneda/pasarela/MSI se valida aparte.
  if (expected.source && matchKey('source') !== expected.source) return false
  if (expected.siteId && matchKey('siteId') !== expected.siteId) return false
  if (expected.formSiteId && matchKey('formSiteId') !== expected.formSiteId) return false
  if (expected.paymentBlockId && matchKey('paymentBlockId') !== expected.paymentBlockId) return false
  if (expectedPageIds.length && actualPageIds.length && !expectedPageIds.some(pageId => actualPageIds.includes(pageId))) return false
  return true
}

function normalizeMoneyCents(value) {
  const amount = Number(value)
  return Number.isFinite(amount) ? Math.round(amount * 100) : 0
}

function normalizePaymentMsiSnapshot(value) {
  if (!value || typeof value !== 'object') return { enabled: false, maxInstallments: 0 }
  const maxInstallments = Math.trunc(Number(value.maxInstallments || value.max_installments || value.months || value.installments || 0))
  const enabled = Boolean(value.enabled) && maxInstallments > 1
  return {
    enabled,
    maxInstallments: enabled ? maxInstallments : 0
  }
}

function normalizePaymentSubscriptionSnapshot(value) {
  if (!value || typeof value !== 'object') return { intervalType: '', intervalCount: 0 }
  const intervalType = cleanString(value.intervalType || value.interval_type || value.interval, 40).toLowerCase()
  const intervalCount = Math.trunc(Number(value.intervalCount || value.interval_count || value.every || 0))
  return {
    intervalType,
    intervalCount: Number.isFinite(intervalCount) && intervalCount > 0 ? intervalCount : 0
  }
}

function paymentGateMatchesCurrentSnapshot(status, paymentGate = {}) {
  if (!status) return false

  const metadata = status.metadata && typeof status.metadata === 'object' ? status.metadata : {}
  const metadataGate = metadata.paymentGate && typeof metadata.paymentGate === 'object'
    ? metadata.paymentGate
    : {}
  const expectedGateway = cleanString(paymentGate.gateway).toLowerCase()
  const actualGateway = cleanString(metadataGate.gateway || status.provider).toLowerCase()
  if (expectedGateway && actualGateway && actualGateway !== expectedGateway) return false

  if (normalizeMoneyCents(status.amount) !== normalizeMoneyCents(paymentGate.amount)) return false

  const expectedCurrency = cleanString(paymentGate.currency).toUpperCase()
  const actualCurrency = cleanString(status.currency || metadataGate.currency).toUpperCase()
  if (expectedCurrency && actualCurrency && actualCurrency !== expectedCurrency) return false

  const expectedMode = cleanString(paymentGate.mode).toLowerCase()
  const recordedMode = cleanString(metadataGate.mode).toLowerCase()
  if (recordedMode && recordedMode !== expectedMode) return false

  const expectedMsi = normalizePaymentMsiSnapshot(paymentGate.msi)
  const recordedMsi = normalizePaymentMsiSnapshot(metadataGate.msi || metadata.stripeInstallments)
  if (expectedMsi.enabled || recordedMsi.enabled) {
    if (expectedMsi.enabled !== recordedMsi.enabled) return false
    if (expectedMsi.maxInstallments !== recordedMsi.maxInstallments) return false
  }

  const expectedBillingType = cleanString(paymentGate.billingType).toLowerCase() === 'subscription' ? 'subscription' : 'single'
  const recordedBillingType = cleanString(metadataGate.billingType || metadataGate.billing_type || metadata.billingType || metadata.billing_type).toLowerCase()
  if (recordedBillingType && recordedBillingType !== expectedBillingType) return false

  if (expectedBillingType === 'subscription') {
    if (recordedBillingType !== 'subscription') return false
    const expectedSubscription = normalizePaymentSubscriptionSnapshot(paymentGate.subscription)
    const recordedSubscription = normalizePaymentSubscriptionSnapshot(metadataGate.subscription || metadata.subscription)
    if ((expectedSubscription.intervalType || 'monthly') !== (recordedSubscription.intervalType || 'monthly')) return false
    if ((expectedSubscription.intervalCount || 1) !== (recordedSubscription.intervalCount || 1)) return false
  }

  return true
}

function paymentGateMatchesCurrentSitePayment(status, expected = {}, paymentGate = {}) {
  return paymentGateMatchesAnySiteContext(status, expected) && paymentGateMatchesCurrentSnapshot(status, paymentGate)
}

function buildSitePaymentRequiredResponse(paymentGate, paymentStatus = {}) {
  return {
    paymentRequired: true,
    publicPaymentId: cleanString(paymentStatus.publicPaymentId || paymentStatus.public_payment_id),
    paymentUrl: cleanString(paymentStatus.paymentUrl || paymentStatus.payment_url),
    paymentStatus: cleanString(paymentStatus.status || 'sent'),
    paymentProvider: cleanString(paymentStatus.provider || paymentGate.gateway),
    paymentGateway: paymentGate.gateway,
    amount: Number(paymentStatus.amount || paymentGate.amount) || paymentGate.amount,
    currency: cleanString(paymentStatus.currency || paymentGate.currency) || paymentGate.currency,
    productName: paymentGate.productName,
    buttonText: paymentGate.buttonText,
    pendingMessage: paymentGate.pendingMessage,
    paidMessage: paymentGate.paidMessage,
    paymentBlockId: cleanString(paymentGate.blockId),
    blockPageId: cleanString(paymentGate.blockPageId),
    message: paymentGate.pendingMessage || 'Completa el pago para continuar.'
  }
}

async function resolveSitePaymentGate({ req, body, site, paymentGate, contact, nativeFormContext, submittedPageId }) {
  const paymentPageId = cleanString(paymentGate.blockPageId || submittedPageId)
  const expected = {
    source: 'site_form',
    siteId: site.id,
    formSiteId: nativeFormContext.formSiteId || site.id,
    pageId: paymentPageId,
    submittedPageId,
    blockPageId: paymentPageId,
    paymentBlockId: cleanString(paymentGate.blockId)
  }
  // Para ACEPTAR un pago ya realizado basta con que sea del mismo sitio + bloque: el
  // checkout embebido inline crea su link con source 'site_checkout', no 'site_form'.
  const matchExpected = {
    siteId: site.id,
    pageId: paymentPageId,
    blockPageId: paymentPageId,
    paymentBlockId: cleanString(paymentGate.blockId)
  }
  const existingPublicPaymentId = getBodyPaymentPublicId(body)

  if (existingPublicPaymentId) {
    const pendingStatus = await getPaymentGateStatus(existingPublicPaymentId)
    if (pendingStatus?.paid && paymentGateMatchesCurrentSitePayment(pendingStatus, matchExpected, paymentGate)) {
      return { paid: true, status: pendingStatus }
    }
    if (pendingStatus && paymentGateMatchesCurrentSitePayment(pendingStatus, matchExpected, paymentGate)) {
      return {
        paid: false,
        response: buildSitePaymentRequiredResponse(paymentGate, pendingStatus)
      }
    }
  }

  const result = await createPaymentGateLink(paymentGate, {
    baseUrl: getRequestBaseUrl(req),
    contact,
    source: 'site_form',
    metadata: {
      siteId: site.id,
      formSiteId: nativeFormContext.formSiteId || site.id,
      formSiteName: nativeFormContext.formSiteName || site.name || '',
      pageId: paymentPageId,
      submittedPageId,
      blockPageId: paymentPageId,
      paymentBlockId: cleanString(paymentGate.blockId),
      paymentGate: expected
    }
  })

  return {
    paid: false,
    response: buildSitePaymentRequiredResponse(paymentGate, {
      publicPaymentId: result.publicPaymentId,
      paymentUrl: result.paymentUrl,
      provider: paymentGate.gateway,
      status: 'sent',
      amount: paymentGate.amount,
      currency: paymentGate.currency
    })
  }
}

export async function getPublicSitePaymentStatus(publicPaymentId) {
  const status = await getPaymentGateStatus(publicPaymentId)
  if (!status) {
    const error = new Error('Pago no encontrado')
    error.status = 404
    throw error
  }

  return {
    publicPaymentId: status.publicPaymentId,
    paymentUrl: status.paymentUrl,
    provider: status.provider,
    status: status.status,
    paid: status.paid,
    amount: status.amount,
    currency: status.currency,
    updatedAt: status.updatedAt
  }
}

function buildSiteCheckoutMountResponse(paymentGate = {}, context = {}, keys = {}) {
  const msi = paymentGate.msi && paymentGate.msi.enabled && paymentGate.msi.maxInstallments > 1
    ? { enabled: true, maxInstallments: paymentGate.msi.maxInstallments }
    : null
  return {
    provider: cleanString(keys.provider) || paymentGate.gateway,
    // Llaves PÚBLICAS del SDK (seguras de exponer). Secretos NUNCA. Sin clientSecret aquí:
    // Stripe se monta en modo diferido y el intent se crea al cobrar.
    publishableKey: cleanString(keys.publishableKey),
    publicKey: cleanString(keys.publicKey),
    apiKey: cleanString(keys.apiKey),
    paymentUrl: cleanString(keys.paymentUrl || keys.hostedPaymentUrl || keys.redirectUrl, 2000),
    hostedPaymentUrl: cleanString(keys.hostedPaymentUrl || keys.paymentUrl || keys.redirectUrl, 2000),
    redirectUrl: cleanString(keys.redirectUrl || keys.hostedPaymentUrl || keys.paymentUrl, 2000),
    paymentMode: cleanString(keys.paymentMode),
    instantProduct: keys.instantProduct || null,
    customerInformation: keys.customerInformation || null,
    // Reanudación: si un pago previo (misma sesión) ya está pagado.
    paid: Boolean(keys.paid),
    publicPaymentId: cleanString(keys.publicPaymentId),
    status: cleanString(keys.status),
    amount: paymentGate.amount,
    currency: paymentGate.currency,
    productName: paymentGate.productName,
    description: paymentGate.description,
    buttonText: paymentGate.buttonText,
    pendingMessage: paymentGate.pendingMessage,
    paidMessage: paymentGate.paidMessage,
    billingType: paymentGate.billingType || 'single',
    subscription: paymentGate.subscription || null,
    installments: msi,
    msi: paymentGate.msi || null,
    blockId: cleanString(context.blockId),
    blockPageId: cleanString(context.blockPageId)
  }
}

// Resuelve el sitio + bloque de pago de una petición pública de checkout. El monto,
// pasarela, modo y MSI vienen SIEMPRE del bloque PERSISTIDO (nunca del cliente).
async function resolveSiteCheckoutBlock(req, body = {}) {
  const { host, submittedSiteId, domainResolution, previewContext } = await resolvePublicRequestAccess(req, body, {})
  const site = submittedSiteId
    ? await getSite(submittedSiteId, { includeBlocks: false, includeSubmissions: false })
    : await findSiteByRoutePath(req.path)

  if (!site) { const error = new Error('Site público no encontrado'); error.status = 404; throw error }
  if (!canExecutePublicSiteAction(site, previewContext)) { const error = new Error('Este site no esta publicado'); error.status = 404; throw error }

  site.domain = domainResolution.domain || host
  site.blocks = await hydrateEmbeddedForms(await listSiteBlocks(site.id))

  const blockId = cleanString(body.blockId || body.block_id || body.meta?.blockId)
  const pageId = cleanString(body.pageId || body.page_id || body.meta?.pageId || body.meta?.page_id)
  const context = findEnabledPaymentBlockById(site.blocks, site, blockId)
  if (!context) { const error = new Error('Bloque de pago no encontrado o deshabilitado'); error.status = 404; throw error }
  validatePaymentBlockRequestContext(context, { blockId, pageId })

  return { site, context, paymentGate: context.paymentGate, baseUrl: getRequestBaseUrl(req), expectedBlockId: cleanString(context.blockId) }
}

// Arranca el checkout embebido SIN crear ningún registro de pago: solo devuelve las llaves
// públicas del proveedor para montar el SDK. Abrir la página NO genera pagos incompletos;
// la fila se crea únicamente al cobrar (paySiteCheckout). Si el runtime re-manda un pago
// previo (misma sesión) ya pagado, responde con el estado para correr la acción de éxito.
export async function initSitePaymentCheckout(req, body = {}) {
  const { site, context, paymentGate, baseUrl, expectedBlockId } = await resolveSiteCheckoutBlock(req, body)
  enforcePublicSubmitRateLimit(req, `checkout-init:${site.id}:${expectedBlockId}`)

  const existing = getBodyPaymentPublicId(body)
  if (existing) {
    const pending = await getPaymentGateStatus(existing)
    const sameContext = paymentGateMatchesCurrentSitePayment(pending, {
      siteId: site.id,
      pageId: cleanString(context.blockPageId),
      blockPageId: cleanString(context.blockPageId),
      paymentBlockId: expectedBlockId
    }, paymentGate)
    if (pending && pending.paid && sameContext) {
      return buildSiteCheckoutMountResponse(paymentGate, context, { paid: true, publicPaymentId: existing, status: pending.status })
    }
    if (pending && !pending.paid && sameContext && paymentGate.billingType === 'subscription') {
      const paymentUrl = cleanString(pending.paymentUrl, 2000)
      if (paymentUrl) {
        return buildSiteCheckoutMountResponse(paymentGate, context, {
          provider: pending.provider || paymentGate.gateway,
          publicPaymentId: existing,
          status: pending.status,
          paymentUrl,
          hostedPaymentUrl: paymentUrl,
          redirectUrl: paymentUrl
        })
      }
    }
    if (pending && !pending.paid && sameContext && paymentGate.gateway === 'rebill') {
      const rebillCheckout = await getPaymentGateCheckoutDescriptor(existing, { baseUrl })
      if (rebillCheckout) {
        return buildSiteCheckoutMountResponse(paymentGate, context, {
          ...rebillCheckout,
          provider: 'rebill',
          publicPaymentId: existing,
          status: pending.status
        })
      }
    }
  }

  const keys = await getPaymentGateCheckoutKeys(paymentGate.gateway, paymentGate.mode === 'test' ? 'test' : '')
  return buildSiteCheckoutMountResponse(paymentGate, context, keys)
}

// Crea el registro de pago (fila) y COBRA — SOLO cuando el cliente intenta pagar de verdad.
// El monto viene del bloque persistido (nunca del cliente). Stripe devuelve clientSecret para
// confirmar en el cliente; Conekta/MP cobran con el token recibido.
// Un RECHAZO real de tarjeta (banco/pasarela dice "no": fondos, robada, etc.) es una
// senal de venta que SI queremos ver en el CRM. Un error de sistema/config/red o un
// abandono NO: solo ensuciaria la tabla (un visitante podria reintentar decenas de
// veces). Lo distinguimos por el status/payload que la pasarela adjunta al error.
function isCardDeclineError(error) {
  if (!error) return false
  if (Number(error.status) === 402) return true
  const parts = [cleanString(error?.message)]
  try { parts.push(JSON.stringify(error?.payload || {})) } catch (_) {}
  const blob = parts.join(' ').toLowerCase()
  return /(declin|rechaz|rejected|insufficient|fondos insuficientes|do_not_honor|do not honor|card_declined|lost_card|stolen_card|expired_card|expirada|incorrect_(cvc|number|zip|pin)|invalid_cvc|fraud|pickup_card|card_not_supported|not_permitted|denied_by)/.test(blob)
}

// El cargo del checkout de sitio no se concreto. La fila se crea ANTES del cargo (lo
// exige el flujo diferido de Stripe), asi que aqui decidimos su destino: si fue un
// RECHAZO real de tarjeta la dejamos 'failed' (visible + notificacion); si fue un error
// de sistema/config/red o un abandono, BORRAMOS la fila recien creada para no acumular
// basura en la tabla de pagos. Solo aplica a filas aun no resueltas.
async function finalizeFailedSiteCheckout(publicPaymentId, error) {
  const pubId = cleanString(publicPaymentId)
  if (!pubId) return
  const row = await db.get('SELECT * FROM payments WHERE public_payment_id = ?', [pubId]).catch(() => null)
  if (!row) return
  const status = cleanString(row.status).toLowerCase()
  const NON_TERMINAL = ['', 'sent', 'pending', 'processing', 'requires_action', 'requires_payment_method', 'incomplete', 'draft', 'initiated']
  if (!NON_TERMINAL.includes(status)) return
  if (isCardDeclineError(error)) {
    await db.run("UPDATE payments SET status = 'failed', updated_at = CURRENT_TIMESTAMP WHERE id = ?", [row.id]).catch(() => {})
    await sendPaymentNotification({ ...row, status: 'failed', previousStatus: row.status || '' }).catch(() => {})
  } else {
    await db.run('DELETE FROM payments WHERE id = ?', [row.id]).catch(() => {})
  }
}

function getSiteSubscriptionPaymentMethod(gateway = '') {
  const provider = cleanString(gateway).toLowerCase()
  if (provider === 'mercadopago') return 'mercadopago_subscription'
  if (provider === 'rebill') return 'rebill_subscription'
  if (provider === 'conekta') return 'conekta_link'
  if (provider === 'stripe') return 'stripe_link'
  return ''
}

function getSiteSubscriptionStartUrl(subscription = {}) {
  return cleanString(
    subscription.subscriptionStartUrl ||
    subscription.stripeCheckoutUrl ||
    subscription.conektaCheckoutUrl ||
    subscription.mercadoPagoSandboxInitPoint ||
    subscription.mercadoPagoInitPoint ||
    subscription.rebillPaymentLinkUrl ||
    subscription.rebillCheckoutUrl,
    2000
  )
}

async function createSiteSubscriptionCheckout({ site, context, paymentGate, baseUrl, expectedBlockId, payer = {}, body = {} }) {
  const provider = cleanString(paymentGate.gateway).toLowerCase()
  const paymentMethod = getSiteSubscriptionPaymentMethod(provider)
  if (!paymentMethod) {
    const error = new Error('Esta pasarela no soporta suscripciones en Sites.')
    error.status = 400
    throw error
  }

  const payerEmail = cleanString(payer.email)
  const payerPhone = cleanString(payer.phone)
  if (!payerEmail || !payerPhone) {
    const error = new Error('Escribe correo y teléfono para crear la suscripción.')
    error.status = 400
    throw error
  }

  let checkoutContactId = cleanString(body.contactId || payer.contactId || payer.contact_id)
  if (!checkoutContactId) {
    const upserted = await upsertContactFromSubmissionWithResult({
      site,
      contact: {
        email: payerEmail,
        phone: payerPhone,
        fullName: cleanString(payer.name || payer.fullName) || payerEmail || payerPhone
      },
      meta: {
        pageUrl: cleanString(body.pageUrl || body.page_url),
        visitorId: cleanString(body.visitorId || body.visitor_id)
      }
    }).catch(() => null)
    checkoutContactId = upserted?.contactId || ''
  }

  if (!checkoutContactId) {
    const error = new Error('No se pudo crear o encontrar el contacto para esta suscripción.')
    error.status = 400
    throw error
  }

  const subscriptionConfig = paymentGate.subscription && typeof paymentGate.subscription === 'object'
    ? paymentGate.subscription
    : {}
  const intervalType = cleanString(subscriptionConfig.intervalType || subscriptionConfig.interval_type || 'monthly').toLowerCase() || 'monthly'
  const intervalCount = Math.max(1, Math.trunc(Number(subscriptionConfig.intervalCount || subscriptionConfig.interval_count || 1) || 1))
  if (provider === 'conekta' && intervalType === 'daily') {
    const error = new Error('Conekta no acepta suscripciones diarias. Usa semanal, mensual o anual.')
    error.status = 400
    throw error
  }
  if (provider === 'rebill' && !['monthly', 'yearly'].includes(intervalType)) {
    const error = new Error('Rebill sólo acepta suscripciones mensuales o anuales.')
    error.status = 400
    throw error
  }
  const subscription = await createSubscription({
    contactId: checkoutContactId,
    contactName: cleanString(payer.name || payer.fullName),
    contactEmail: payerEmail,
    contactPhone: payerPhone,
    name: paymentGate.productName,
    description: paymentGate.description,
    amount: paymentGate.amount,
    currency: paymentGate.currency,
    intervalType,
    intervalCount,
    status: 'incomplete',
    paymentMethod,
    paymentProvider: provider,
    paymentMode: paymentGate.mode === 'test' ? 'test' : undefined,
    source: 'site_checkout_subscription',
    baseUrl,
    metadata: {
      source: 'site_checkout_subscription',
      siteId: site.id,
      siteName: site.name || '',
      pageId: cleanString(context.blockPageId),
      blockPageId: cleanString(context.blockPageId),
      paymentBlockId: expectedBlockId,
      paymentGate: {
        source: 'site_checkout_subscription',
        siteId: site.id,
        pageId: cleanString(context.blockPageId),
        blockPageId: cleanString(context.blockPageId),
        paymentBlockId: expectedBlockId,
        gateway: provider,
        billingType: 'subscription',
        amount: paymentGate.amount,
        currency: paymentGate.currency,
        productName: paymentGate.productName,
        mode: paymentGate.mode,
        subscription: {
          intervalType,
          intervalCount
        }
      }
    }
  })

  const subscriptionStartUrl = getSiteSubscriptionStartUrl(subscription)
  if (!subscriptionStartUrl) {
    const error = new Error('No se pudo crear el checkout de suscripción.')
    error.status = 502
    throw error
  }

  return {
    publicPaymentId: cleanString(subscription.subscriptionStartPublicPaymentId),
    provider,
    billingType: 'subscription',
    subscriptionId: subscription.id,
    subscriptionStartUrl,
    paymentUrl: subscriptionStartUrl,
    checkoutUrl: subscriptionStartUrl,
    status: cleanString(subscription.subscriptionStartPaymentStatus || subscription.status || 'pending'),
    paidMessage: paymentGate.paidMessage
  }
}

export async function paySiteCheckout(req, body = {}) {
  const { site, context, paymentGate, baseUrl, expectedBlockId } = await resolveSiteCheckoutBlock(req, body)
  enforcePublicSubmitRateLimit(req, `checkout-pay:${site.id}:${expectedBlockId}`)
  const payer = body.payer && typeof body.payer === 'object' ? body.payer : {}

  if (paymentGate.billingType === 'subscription') {
    return createSiteSubscriptionCheckout({ site, context, paymentGate, baseUrl, expectedBlockId, payer, body })
  }

  // Liga el pago a un contacto: si el checkout (o el embudo) trae correo/telefono,
  // resolvemos/creamos el contacto con el MISMO helper que usan los formularios,
  // para que payments.contact_id no quede null y el Purchase de Meta pueda dispararse.
  let checkoutContactId = cleanString(body.contactId || payer.contactId || payer.contact_id)
  if (!checkoutContactId && (cleanString(payer.email) || cleanString(payer.phone))) {
    const upserted = await upsertContactFromSubmissionWithResult({
      site,
      contact: {
        email: cleanString(payer.email),
        phone: cleanString(payer.phone),
        fullName: cleanString(payer.name || payer.fullName)
      },
      meta: {
        pageUrl: cleanString(body.pageUrl || body.page_url),
        visitorId: cleanString(body.visitorId || body.visitor_id)
      }
    }).catch(() => null)
    checkoutContactId = upserted?.contactId || ''
  }

  const result = await createPaymentGateLink(paymentGate, {
    baseUrl,
    contact: {
      contactId: checkoutContactId,
      name: cleanString(payer.name || payer.fullName),
      email: cleanString(payer.email),
      phone: cleanString(payer.phone)
    },
    source: 'site_checkout',
    metadata: {
      siteId: site.id,
      siteName: site.name || '',
      pageId: cleanString(context.blockPageId),
      blockPageId: cleanString(context.blockPageId),
      paymentBlockId: expectedBlockId,
      paymentGate: {
        source: 'site_checkout',
        siteId: site.id,
        pageId: cleanString(context.blockPageId),
        blockPageId: cleanString(context.blockPageId),
        paymentBlockId: expectedBlockId
      }
    }
  })
  const publicPaymentId = result.publicPaymentId

  if (paymentGate.gateway === 'rebill' && !cleanString(body.rebillPaymentId || body.rebill_payment_id || body.paymentId || body.payment_id)) {
    const rebillCheckout = await getPaymentGateCheckoutDescriptor(publicPaymentId, { baseUrl })
    const paymentUrl = cleanString(result.paymentUrl || rebillCheckout?.hostedPaymentUrl || rebillCheckout?.paymentUrl || rebillCheckout?.redirectUrl, 2000)
    return {
      publicPaymentId,
      provider: 'rebill',
      paymentUrl,
      status: cleanString(rebillCheckout?.status || 'pending'),
      rebillCheckout,
      paidMessage: paymentGate.paidMessage
    }
  }

  let charge
  try {
    charge = await createPaymentGateCharge(publicPaymentId, paymentGate.gateway, {
      tokenId: cleanString(body.tokenId || body.token_id),
      token: cleanString(body.token),
      rebillPaymentId: cleanString(body.rebillPaymentId || body.rebill_payment_id || body.paymentId || body.payment_id),
      paymentMethodId: cleanString(body.paymentMethodId || body.payment_method_id),
      issuerId: cleanString(body.issuerId || body.issuer_id),
      installments: body.installments,
      email: cleanString(payer.email),
      phone: cleanString(payer.phone),
      customerName: cleanString(payer.name || payer.fullName),
      payer
    }, { baseUrl })
  } catch (error) {
    // Rechazo real -> 'failed' (se ve); error/abandono -> se borra la fila. Nunca truena.
    await finalizeFailedSiteCheckout(publicPaymentId, error).catch(() => {})
    throw error
  }

  return {
    publicPaymentId,
    provider: charge.provider,
    clientSecret: cleanString(charge.clientSecret),
    clipPaymentId: cleanString(charge.clipPaymentId),
    rebillPaymentId: cleanString(charge.rebillPaymentId),
    pendingAction: charge.pendingAction || null,
    status: cleanString(charge.status),
    statusDetail: cleanString(charge.statusDetail),
    paidMessage: paymentGate.paidMessage
  }
}

// Prepara MSI controlado de Stripe en el checkout embebido de Sites: crea/reusa
// la fila MSI-ready, crea un PaymentIntent con el PaymentMethod seguro de Stripe,
// y devuelve available_plans ya filtrados por el maximo local del bloque.
export async function prepareSiteCheckoutInstallments(req, body = {}) {
  const { site, context, paymentGate, baseUrl, expectedBlockId } = await resolveSiteCheckoutBlock(req, body)
  enforcePublicSubmitRateLimit(req, `checkout-prepare:${site.id}:${expectedBlockId}`)

  // Solo Stripe con MSI elegible (MXN + monto mínimo + msi on) ofrece este flujo. Fuente
  // de verdad = helper compartido (misma regla que el preview del editor y el runtime).
  const eligibility = msiEligibility({
    gateway: paymentGate.gateway,
    currency: paymentGate.currency,
    amount: paymentGate.amount,
    msi: paymentGate.msi
  })
  if (paymentGate.gateway !== 'stripe' || !eligibility.insideElement) {
    const error = new Error('Este bloque no ofrece meses sin intereses con Stripe.')
    error.status = 400
    throw error
  }

  const payer = body.payer && typeof body.payer === 'object' ? body.payer : {}

  // Liga el pago a un contacto (idéntico a paySiteCheckout) para guardar la tarjeta
  // off_session y poder disparar el Purchase de Meta.
  let checkoutContactId = cleanString(body.contactId || payer.contactId || payer.contact_id)
  if (!checkoutContactId && (cleanString(payer.email) || cleanString(payer.phone))) {
    const upserted = await upsertContactFromSubmissionWithResult({
      site,
      contact: {
        email: cleanString(payer.email),
        phone: cleanString(payer.phone),
        fullName: cleanString(payer.name || payer.fullName)
      },
      meta: {
        pageUrl: cleanString(body.pageUrl || body.page_url),
        visitorId: cleanString(body.visitorId || body.visitor_id)
      }
    }).catch(() => null)
    checkoutContactId = upserted?.contactId || ''
  }

  // Idempotencia de fila: si el runtime reenvía un publicPaymentId previo del MISMO bloque
  // aún NO pagado y con el mismo snapshot de pago, lo reusamos. Si el monto/moneda/MSI
  // cambió en el editor, se ignora y se crea uno nuevo.
  let publicPaymentId = ''
  const existing = getBodyPaymentPublicId(body)
  if (existing) {
    const pending = await getPaymentGateStatus(existing)
    const sameContext = paymentGateMatchesCurrentSitePayment(pending, {
      siteId: site.id,
      pageId: cleanString(context.blockPageId),
      blockPageId: cleanString(context.blockPageId),
      paymentBlockId: expectedBlockId
    }, paymentGate)
    if (pending && !pending.paid && sameContext) publicPaymentId = existing
  }

  if (!publicPaymentId) {
    const result = await createPaymentGateLink(paymentGate, {
      baseUrl,
      contact: {
        contactId: checkoutContactId,
        name: cleanString(payer.name || payer.fullName),
        email: cleanString(payer.email),
        phone: cleanString(payer.phone)
      },
      source: 'site_checkout',
      metadata: {
        siteId: site.id,
        siteName: site.name || '',
        pageId: cleanString(context.blockPageId),
        blockPageId: cleanString(context.blockPageId),
        paymentBlockId: expectedBlockId,
        paymentGate: {
          source: 'site_checkout',
          siteId: site.id,
          pageId: cleanString(context.blockPageId),
          blockPageId: cleanString(context.blockPageId),
          paymentBlockId: expectedBlockId
        }
      }
    })
    publicPaymentId = result.publicPaymentId
  }

  const paymentMethodId = cleanString(body.paymentMethodId || body.payment_method_id)
  if (!paymentMethodId) {
    const error = new Error('Falta la tarjeta segura de Stripe para consultar los meses disponibles.')
    error.status = 400
    throw error
  }

  const prepared = await preparePublicStripeInstallmentPlans(publicPaymentId, {
    paymentMethodId,
    savePaymentMethod: true
  })

  return {
    publicPaymentId,
    paymentIntentId: prepared.paymentIntentId,
    clientSecret: prepared.clientSecret,
    publishableKey: prepared.publishableKey,
    status: prepared.status,
    maxInstallments: prepared.maxInstallments,
    availablePlans: prepared.availablePlans
  }
}

export async function createSubmissionFromRequest(req, body = {}, options = {}) {
  const {
    host,
    submittedSiteId,
    domainResolution,
    previewContext
  } = await resolvePublicRequestAccess(req, body, options)
  const site = submittedSiteId
    ? await getSite(submittedSiteId, { includeBlocks: false, includeSubmissions: false })
    : await findSiteByRoutePath(req.path)

  if (!site) {
    const error = new Error('Site público no encontrado')
    error.status = 404
    throw error
  }

  if (!canExecutePublicSiteAction(site, previewContext)) {
    const error = new Error('Este site no esta publicado')
    error.status = 404
    throw error
  }

  // (TRK-004) Anti-abuso del submit público: rate limiting por IP+site + honeypot.
  // Se aplica solo a envíos reales (no a pasos intermedios sin finalSubmit) para no
  // estrangular la navegación legítima de funnels multi-paso. Va ANTES de crear
  // contactos, disparar automatizaciones o enviar eventos a CAPI.
  const isCountedPublicSubmit = normalizeBoolean(
    body.finalSubmit ||
    body.final_submit ||
    body.meta?.formFinalSubmit ||
    body.meta?.form_final_submit
  ) || site.siteType !== 'standard_form'
  if (isCountedPublicSubmit) {
    // Honeypot: si un bot llenó el campo señuelo, descartar en silencio fingiendo éxito.
    if (isPublicSubmitHoneypotTriggered(body)) {
      logger.warn(`Submit público descartado por honeypot (site ${site.id}, ip ${getClientIp(req)})`)
      return {
        submissionId: null,
        siteId: site.id,
        contactId: null,
        status: 'ok',
        message: '',
        redirectUrl: '',
        rules: {},
        rawFields: {},
        mappedFields: {},
        derivedFields: {},
        capi: { sent: false, reason: 'honeypot' }
      }
    }
    enforcePublicSubmitRateLimit(req, site.id)
  }

  site.domain = domainResolution.domain || host
  if (isImportedHtmlSite(site)) {
    return createImportedSubmissionFromRequest({ req, body, site, host, previewContext })
  }

  site.blocks = await hydrateEmbeddedForms(await listSiteBlocks(site.id))

  const blocks = Array.isArray(site.blocks) && site.blocks.length
    ? site.blocks
    : await hydrateEmbeddedForms(await listSiteBlocks(site.id))
  const submittedPageId = cleanString(body.pageId || body.page_id || body.meta?.pageId || body.meta?.page_id)
  const videoFormGateBlockId = cleanString(
    body.videoFormGateBlockId ||
    body.video_form_gate_block_id ||
    body.meta?.videoFormGateBlockId ||
    body.meta?.video_form_gate_block_id
  )
  const isFinalStandardFormSubmit = site.siteType === 'standard_form' && normalizeBoolean(
    body.finalSubmit ||
    body.final_submit ||
    body.meta?.formFinalSubmit ||
    body.meta?.form_final_submit
  )
  const isRuleSubmit = normalizeBoolean(
    body.ruleSubmit ||
    body.rule_submit ||
    body.meta?.ruleSubmit ||
    body.meta?.rule_submit
  )
  const siteWithBlocks = { ...site, blocks }
  const videoFormGateContext = getVideoFormGateSubmissionContext(siteWithBlocks, blocks, videoFormGateBlockId)
  const orderedSubmissionBlocks = site.siteType === 'interactive_form'
    ? getInteractiveFormBlocks(siteWithBlocks)
    : blocks
  const defaultSubmissionBlocks = site.siteType === 'standard_form'
    ? isFinalStandardFormSubmit
      ? getStandardFormContentBlocks(siteWithBlocks, blocks)
      : isRuleSubmit && submittedPageId
        ? getStandardFormReachedBlocks(siteWithBlocks, blocks, submittedPageId)
        : submittedPageId
        ? getStandardFormReachedBlocks(siteWithBlocks, blocks, submittedPageId)
        : orderedSubmissionBlocks
    : site.siteType === 'landing_page' && submittedPageId
      ? getPageBlocks(siteWithBlocks, submittedPageId)
      : orderedSubmissionBlocks
  const submissionBlocks = videoFormGateContext ? videoFormGateContext.blocks : defaultSubmissionBlocks
  const landingEmbeddedFormContext = videoFormGateContext
    ? null
    : getLandingEmbeddedFormSubmissionContext(siteWithBlocks, defaultSubmissionBlocks)
  const effectiveSubmittedPageId = submittedPageId || (videoFormGateContext ? DEFAULT_FUNNEL_PAGE_ID : '')
  if (
    site.siteType === 'standard_form' &&
    isRuleSubmit &&
    !isFinalStandardFormSubmit &&
    !normalizeSubmitIncompleteOnExit(site.theme)
  ) {
    const { responses: skippedResponses } = normalizeSubmissionResponses(submissionBlocks, body.responses || {}, {
      skipRequired: true
    })
    let ruleEvaluation = evaluateSubmissionRules(submissionBlocks, skippedResponses)
    const ruleTargetPageId = ruleEvaluation.targetPageId ||
      getFieldTargetPageId(siteWithBlocks, blocks, ruleEvaluation.targetBlockId)
    if (ruleTargetPageId && ruleTargetPageId !== ruleEvaluation.targetPageId) {
      ruleEvaluation = { ...ruleEvaluation, targetPageId: ruleTargetPageId }
    }
    const ruleRedirectUrl = ruleEvaluation.redirectUrl ||
      (ruleTargetPageId ? buildPageHref(ruleTargetPageId, { site }) : '')
    const submissionRedirectUrl = ruleRedirectUrl || getStandardFormResultRedirectUrl(siteWithBlocks, ruleEvaluation, {
      isFinalStandardFormSubmit: false
    })

    return {
      submissionId: '',
      siteId: site.id,
      contactId: null,
      contactName: '',
      contactEmail: '',
      contactPhone: '',
      status: ruleEvaluation.status,
      message: getSiteFinalMessage(site, ruleEvaluation),
      redirectUrl: submissionRedirectUrl,
      rules: ruleEvaluation,
      rawFields: {},
      mappedFields: {},
      derivedFields: {},
      skipped: true,
      capi: { sent: false, reason: 'incomplete_exit_disabled' }
    }
  }
  const immediateDisqualifySubmit = normalizeBoolean(
    body.meta?.immediateDisqualify ||
    body.meta?.immediate_disqualify ||
    (body.meta?.ruleAction === 'disqualify' ? true : false) ||
    (body.meta?.rule_action === 'disqualify' ? true : false)
  )
  const { responses, errors } = normalizeSubmissionResponses(submissionBlocks, body.responses || {}, {
    skipRequired: immediateDisqualifySubmit
  })
  if (errors.length) {
    const error = new Error(errors.join(', '))
    error.status = 400
    throw error
  }

  let ruleEvaluation = evaluateSubmissionRules(submissionBlocks, responses)
  const ruleTargetPageId = ruleEvaluation.targetPageId ||
    getFieldTargetPageId(siteWithBlocks, blocks, ruleEvaluation.targetBlockId)
  if (ruleTargetPageId && ruleTargetPageId !== ruleEvaluation.targetPageId) {
    ruleEvaluation = { ...ruleEvaluation, targetPageId: ruleTargetPageId }
  }
  const ruleRedirectUrl = ruleEvaluation.redirectUrl ||
    (ruleTargetPageId ? buildPageHref(ruleTargetPageId, { site }) : '')
  const submissionRedirectUrl = ruleRedirectUrl || getStandardFormResultRedirectUrl(siteWithBlocks, ruleEvaluation, {
    isFinalStandardFormSubmit
  })

  const meta = {
    ...(body.meta && typeof body.meta === 'object' ? body.meta : {}),
    ...(videoFormGateContext ? {
      videoFormGate: true,
      videoFormGateBlockId: videoFormGateContext.videoBlockId,
      formSiteId: videoFormGateContext.formSiteId,
      formSiteName: videoFormGateContext.formSiteName
    } : {}),
    ...(!videoFormGateContext && landingEmbeddedFormContext?.meta?.enabled ? {
      embeddedFormMeta: landingEmbeddedFormContext.meta
    } : {}),
    host,
    previewSession: Boolean(previewContext),
    previewPageId: previewContext?.pageId || '',
    rules: ruleEvaluation,
    userAgent: req.headers['user-agent'] || '',
    submittedAt: new Date().toISOString()
  }
  const nativeLayers = buildNativeSubmissionLayers({ site, blocks: submissionBlocks, responses })
  const inferredContact = inferContactFromResponses(collectFieldBlocks(submissionBlocks), responses)
  const finalMessageTheme = videoFormGateContext?.formTheme || landingEmbeddedFormContext?.formTheme || null
  const finalMessageSite = finalMessageTheme
    ? { ...site, theme: { ...(site.theme || {}), ...finalMessageTheme } }
    : site
  const nativeFormContextForPayment = videoFormGateContext || landingEmbeddedFormContext || getNativeFormContext(site, submissionBlocks)
  const paymentGate = resolveSitePaymentGateConfig(siteWithBlocks, {
    videoFormGateContext,
    landingEmbeddedFormContext,
    submissionBlocks,
    defaultSubmissionBlocks,
    allBlocks: blocks
  })
  if (shouldSkipTracking({ req, body, meta, previewContext }) && (Boolean(previewContext) || !(await isMetaTestModeActive()))) {
    return {
      submissionId: createRistakId('site_preview_submission'),
      siteId: site.id,
      contactId: null,
      contactName: inferredContact.fullName || '',
      contactEmail: inferredContact.email || '',
      contactPhone: inferredContact.phone || '',
      status: ruleEvaluation.status,
      message: getSiteFinalMessage(finalMessageSite, ruleEvaluation),
      redirectUrl: submissionRedirectUrl,
      rules: ruleEvaluation,
      rawFields: nativeLayers.rawFields,
      mappedFields: nativeLayers.mappedFields,
      derivedFields: nativeLayers.derivedFields,
      preview: true,
      skipped: true,
      capi: { sent: false, reason: NO_TRACK_REASON }
    }
  }

  if (shouldRequireSitePaymentGate({
    site,
    paymentGate,
    ruleEvaluation,
    isRuleSubmit,
    isFinalStandardFormSubmit,
    submittedPageId: effectiveSubmittedPageId
  })) {
    const paymentResult = await resolveSitePaymentGate({
      req,
      body,
      site,
      paymentGate,
      contact: inferredContact,
      nativeFormContext: nativeFormContextForPayment,
      submittedPageId: effectiveSubmittedPageId
    })
    if (!paymentResult.paid) {
      return {
        submissionId: '',
        siteId: site.id,
        contactId: null,
        contactName: inferredContact.fullName || '',
        contactEmail: inferredContact.email || '',
        contactPhone: inferredContact.phone || '',
        status: 'payment_pending',
        redirectUrl: '',
        rules: ruleEvaluation,
        rawFields: nativeLayers.rawFields,
        mappedFields: nativeLayers.mappedFields,
        derivedFields: nativeLayers.derivedFields,
        skipped: true,
        capi: { sent: false, reason: 'payment_pending' },
        ...paymentResult.response
      }
    }
    meta.paymentGate = {
      required: true,
      publicPaymentId: paymentResult.status.publicPaymentId,
      provider: paymentResult.status.provider,
      amount: paymentResult.status.amount,
      currency: paymentResult.status.currency,
      paidAt: paymentResult.status.paidAt,
      paymentBlockId: cleanString(paymentGate.blockId)
    }
  }

  const contactResult = await upsertContactFromSubmissionWithResult({ site, contact: inferredContact, meta })
  const contactId = contactResult.contactId
  const preparedCustomFields = await upsertNativeContactCustomFields({
    site,
    contactId,
    blocks: submissionBlocks,
    responses
  })
  const preparedUserCustomFields = preparedCustomFields.filter(field => (
    !NATIVE_FORM_CUSTOM_SYSTEM_FIELDS.has(cleanString(field.fieldKey || field.key))
  ))
  const mappedFields = {
    ...(Object.keys(nativeLayers.mappedFields.standard || {}).length ? { standard: nativeLayers.mappedFields.standard } : {}),
    ...(Object.keys(nativeLayers.mappedFields.system || {}).length ? { system: nativeLayers.mappedFields.system } : {}),
    ...(Object.keys(nativeLayers.mappedFields.custom || {}).length || preparedUserCustomFields.length
      ? { custom: { ...(nativeLayers.mappedFields.custom || {}), ...buildNativeMappedCustomFields(preparedUserCustomFields) } }
      : {})
  }
  const submissionId = createRistakId('site_submission')
  const nativeFormContext = videoFormGateContext || getNativeFormContext(site, submissionBlocks)
  const automationFormResponses = buildNativeAutomationFormResponses({
    blocks: submissionBlocks,
    responses
  })

  Object.assign(meta, {
    submissionId,
    formStatus: ruleEvaluation.status,
    formDisqualified: ruleEvaluation.status === 'disqualified' || ruleEvaluation.disqualified === true,
    formResponses: automationFormResponses,
    rawFields: nativeLayers.rawFields,
    mappedFields,
    derivedFields: nativeLayers.derivedFields
  })

  await db.run(`
    INSERT INTO public_site_submissions (
      id, site_id, form_site_id, contact_id, domain, response_json, raw_fields_json,
      mapped_fields_json, derived_fields_json, meta_json, status, created_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
  `, [
    submissionId,
    site.id,
    nativeFormContext.formSiteId || site.id,
    contactId,
    host,
    jsonString(responses),
    jsonString(nativeLayers.rawFields),
    jsonString(mappedFields),
    jsonString(nativeLayers.derivedFields),
    jsonString(meta),
    ruleEvaluation.status
  ])

  await emitSiteSubmissionAutomationEvents({
    contactResult,
    formEvent: {
      contactId,
      formId: nativeFormContext.formSiteId || site.id,
      formName: nativeFormContext.formSiteName || site.name || '',
      siteId: site.id,
      siteName: site.name || '',
      formSiteId: nativeFormContext.formSiteId || site.id,
      formSiteName: nativeFormContext.formSiteName || site.name || '',
      submissionId,
      formStatus: ruleEvaluation.status,
      status: ruleEvaluation.status,
      formDisqualified: ruleEvaluation.status === 'disqualified' || ruleEvaluation.disqualified === true,
      submittedAt: meta.submittedAt,
      formResponses: automationFormResponses,
      immediateDisqualify: immediateDisqualifySubmit
    },
    contactChangedFields: customFieldChangeKeys(preparedCustomFields)
  })
  const latestContactForMeta = await loadContactForMetaTemplate(contactId, inferredContact)

  const capi = await sendSiteLeadMetaEvent({
    site,
    submissionId,
    submittedPageId: effectiveSubmittedPageId,
    contactId,
    contact: latestContactForMeta,
    requestMeta: {
      req,
      ip: getClientIp(req),
      userAgent: req.headers['user-agent'] || '',
      meta
    }
  })

  await recordNativeSiteConversionEvent({
    site,
    blocks: submissionBlocks,
    submittedPageId: effectiveSubmittedPageId,
    submissionId,
    contactId,
    contact: inferredContact,
    req,
    meta
  }).catch(error => {
    logger.warn(`No se pudo registrar conversion nativa de site ${site.id}: ${error.message}`)
  })

  const responseContact = buildPublicContactPayload(contactId, inferredContact)

  return {
    submissionId,
    siteId: site.id,
    contactId,
    contact: responseContact,
    contactName: responseContact.fullName,
    contactEmail: responseContact.email,
    contactPhone: responseContact.phone,
    status: ruleEvaluation.status,
    message: getSiteFinalMessage(finalMessageSite, ruleEvaluation),
    redirectUrl: submissionRedirectUrl,
    rules: ruleEvaluation,
    rawFields: nativeLayers.rawFields,
    mappedFields,
    derivedFields: nativeLayers.derivedFields,
    capi
  }
}

export async function createMetaPageEventFromRequest(req, body = {}, options = {}) {
  const {
    host,
    domainResolution,
    previewContext
  } = await resolvePublicRequestAccess(req, body, options)

  const siteId = cleanString(body.siteId || body.site_id)
  if (!siteId) {
    const error = new Error('Site requerido')
    error.status = 400
    throw error
  }

  const site = await getSite(siteId, { includeBlocks: false, includeSubmissions: false })
  if (!site) {
    const error = new Error('Site público no encontrado')
    error.status = 404
    throw error
  }

  if (!canExecutePublicSiteAction(site, previewContext)) {
    const error = new Error('Este site no esta publicado')
    error.status = 404
    throw error
  }

  site.domain = domainResolution.domain || host

  // Modo test (código de Test Events activo) fuerza el evento aunque la página
  // esté en anti-tracking en vivo, pero NUNCA en el preview del editor.
  if (shouldSkipTracking({ req, body, previewContext }) && (Boolean(previewContext) || !(await isMetaTestModeActive()))) {
    return { sent: false, reason: NO_TRACK_REASON }
  }

  if (!site.metaCapiEnabled) {
    return { sent: false, reason: 'site_disabled' }
  }

  const pageId = cleanString(body.pageId || body.page_id)
  const eventScope = cleanString(body.eventScope || body.event_scope)
  if (eventScope === 'video_action') {
    const blocks = await hydrateEmbeddedForms(await listSiteBlocks(site.id))
    site.blocks = blocks
    const videoBlockId = cleanString(body.videoBlockId || body.video_block_id)
    const videoActionId = cleanString(body.videoActionId || body.video_action_id)
    const videoActionMeta = getVideoActionMetaEventConfig(site, videoBlockId, videoActionId)
    if (!videoActionMeta) {
      return { sent: false, reason: 'video_action_event_disabled' }
    }

    const meta = {
      ...(body.meta && typeof body.meta === 'object' ? body.meta : {}),
      pageId,
      previewSession: Boolean(previewContext),
      previewPageId: previewContext?.pageId || ''
    }
    const eventId = cleanString(body.eventId || body.event_id) || `site_video_action_${site.id}_${videoBlockId}_${videoActionId}_${crypto.randomUUID()}`
    const contactId = cleanString(body.contactId || body.contact_id || body.meta?.contactId || body.meta?.contact_id)

    return sendSiteVideoActionMetaEvent({
      site,
      block: videoActionMeta.block,
      rule: videoActionMeta.rule,
      eventName: videoActionMeta.eventName,
      parameters: videoActionMeta.parameters,
      eventId,
      contactId,
      requestMeta: {
        req,
        ip: getClientIp(req),
        userAgent: req.headers['user-agent'] || '',
        meta
      }
    })
  }

  const pageMeta = getPageMetaConfig(site, pageId)
  if (!pageMeta || pageMeta.trigger !== 'page_view') {
    return { sent: false, reason: 'page_event_disabled' }
  }

  const meta = {
    ...(body.meta && typeof body.meta === 'object' ? body.meta : {}),
    previewSession: Boolean(previewContext),
    previewPageId: previewContext?.pageId || ''
  }
  const eventId = cleanString(body.eventId || body.event_id) || `site_page_${site.id}_${pageMeta.page.id}_${crypto.randomUUID()}`
  const contactId = cleanString(body.contactId || body.contact_id || body.meta?.contactId || body.meta?.contact_id)

  return sendSitePageMetaEvent({
    site,
    page: pageMeta.page,
    eventName: pageMeta.eventName,
    eventId,
    contactId,
    requestMeta: {
      req,
      ip: getClientIp(req),
      userAgent: req.headers['user-agent'] || '',
      meta
    }
  })
}
